 96→export function EditorLayout() {
 97→  perfCount("EditorLayout");
 98→  const { leftOpen, rightOpen, leftWidth, toggleLeft, toggleRight } =
 99→    usePanelState();
100→  const fileInputRef = useRef<HTMLInputElement>(null);
101→  const [mermaidImportOpen, setMermaidImportOpen] = useState(false);
102→  const [exportDialogOpen, setExportDialogOpen] = useState(false);
103→  const [isBulkEditMode, setIsBulkEditMode] = useState(false);
104→  const [bulkEditFocusTarget, setBulkEditFocusTarget] = useState<{
105→    type: "node" | "edge";
106→    id: string;
107→  } | null>(null);
108→  const [bulkEditHighlightId, setBulkEditHighlightId] = useState<string | null>(null);
109→  const [bulkEditSelectedIds, setBulkEditSelectedIds] = useState<string[]>([]);
110→
111→  // Diff compare mode state
112→  const [isDiffMode, setIsDiffMode] = useState(false);
113→  const [diffStep, setDiffStep] = useState<"import" | "compare">("import");
114→  const [diffBaseLayout, setDiffBaseLayout] = useState<FlowmaidLayout | null>(null);
115→  const [diffBaseFileName, setDiffBaseFileName] = useState<string | null>(null);
116→  const [diffBaseMeta, setDiffBaseMeta] = useState<FileMeta | null>(null);
117→  const [diffCompareLayout, setDiffCompareLayout] = useState<FlowmaidLayout | null>(null);
118→  const [diffCompareFileName, setDiffCompareFileName] = useState<string | null>(null);
119→  const [diffCompareMeta, setDiffCompareMeta] = useState<FileMeta | null>(null);
120→  const [diffFilters, setDiffFilters] = useState<DiffFilters>(DEFAULT_DIFF_FILTERS);
121→  const [diffFlowOpacity, setDiffFlowOpacity] = useState(1);
122→  const [diffResult, setDiffResult] = useState<DiffResult | null>(null);
123→  const [diffViewMode, setDiffViewMode] = useState<"unified" | "sideBySide">("sideBySide");
124→  const [diffFlashTarget, setDiffFlashTarget] = useState<{ id: string; type: "node" | "edge"; seq: number } | null>(null);
125→  const [diffTextCollapsed, setDiffTextCollapsed] = useState(false);
126→  const diffFlashSeqRef = useRef(0);
127→  const diffTextPanelRef = useRef<PanelImperativeHandle>(null);
128→
129→  const { t } = useLocale();
130→  const isEditingComponent = useFlowStore((s) => !!s.editingComponentId);
131→
132→  // Grid snap state (persisted in localStorage, not in undo/redo)
133→  const [gridSnap, setGridSnap] = useState(() => {
134→    if (typeof window === "undefined") return false;
135→    return localStorage.getItem(GRID_SNAP_STORAGE_KEY) === "true";
136→  });
137→  const handleToggleGridSnap = useCallback(() => {
138→    setGridSnap((prev) => {
139→      const next = !prev;
140→      localStorage.setItem(GRID_SNAP_STORAGE_KEY, String(next));
141→      return next;
142→    });
143→  }, []);
144→
145→  // Ghost nodes toggle (persisted in localStorage, default ON)
146→  const [ghostEnabled, setGhostEnabled] = useState(() => {
147→    if (typeof window === "undefined") return true;
148→    const v = localStorage.getItem(GHOST_ENABLED_STORAGE_KEY);
149→    return v === null ? true : v === "true";
150→  });
151→  const handleToggleGhost = useCallback(() => {
152→    setGhostEnabled((prev) => {
153→      const next = !prev;
154→      localStorage.setItem(GHOST_ENABLED_STORAGE_KEY, String(next));
155→      return next;
156→    });
157→  }, []);
158→
159→  useAutoSave();
160→  useKeyboardShortcuts();
161→
162→  // Listen for export/import events
163→  useEffect(() => {
164→    const handleExportEvent = () => {
165→      setExportDialogOpen(true);
166→    };
167→
168→    const handleImportEvent = (e: Event) => {
169→      try {
170→        const content = (e as CustomEvent).detail as string;
171→        const result = deserialize(content);
172→        useFlowStore.getState().loadState(result);
173→        toast.success(locales[useLocaleStore.getState().locale]["importedSuccess"]);
174→      } catch (err) {
175→        toast.error(locales[useLocaleStore.getState().locale]["importFailed"]);
176→        console.error(err);
177→      }
178→    };
179→
180→    window.addEventListener("flowmaid:export", handleExportEvent);
181→    window.addEventListener("flowmaid:import", handleImportEvent);
182→    return () => {
183→      window.removeEventListener("flowmaid:export", handleExportEvent);
184→      window.removeEventListener("flowmaid:import", handleImportEvent);
185→    };
186→  }, []);
187→
188→  const handleExport = useCallback(() => {
189→    setExportDialogOpen(true);
190→  }, []);
191→
192→  const handleImport = useCallback(() => {
193→    fileInputRef.current?.click();
194→  }, []);
195→
196→  const handleFileChange = useCallback(
197→    (e: React.ChangeEvent<HTMLInputElement>) => {
198→      const file = e.target.files?.[0];
199→      if (!file) return;
200→      const reader = new FileReader();
201→      reader.onload = (ev) => {
202→        const content = ev.target?.result as string;
203→        window.dispatchEvent(
204→          new CustomEvent("flowmaid:import", { detail: content })
205→        );
206→      };
207→      reader.readAsText(file);
208→      e.target.value = "";
209→    },
210→    []
211→  );
212→
213→  const handleImportMermaid = useCallback(() => {
214→    setMermaidImportOpen(true);
215→  }, []);
216→
217→  const handleFitView = useCallback(() => {
218→    window.dispatchEvent(new CustomEvent("flowmaid:fitview"));
219→  }, []);
220→
221→  const handleEnterBulkEdit = useCallback(() => {
222→    setBulkEditFocusTarget(null);
223→    setBulkEditHighlightId(null);
224→    setBulkEditSelectedIds([]);
225→    setIsBulkEditMode(true);
226→  }, []);
227→
228→  const handleExitBulkEdit = useCallback(() => {
229→    setIsBulkEditMode(false);
230→    setBulkEditFocusTarget(null);
231→    setBulkEditHighlightId(null);
232→    setBulkEditSelectedIds([]);
233→  }, []);
234→
235→  // Table row click → highlight + zoom
236→  const handleBulkEditFocusNode = useCallback((nodeId: string) => {
237→    setBulkEditSelectedIds([]);
238→    setBulkEditFocusTarget({ type: "node", id: nodeId });
239→    setBulkEditHighlightId(nodeId);
240→  }, []);
241→
242→  const handleBulkEditFocusEdge = useCallback((edgeId: string) => {
243→    setBulkEditSelectedIds([]);
244→    setBulkEditFocusTarget({ type: "edge", id: edgeId });
245→    setBulkEditHighlightId(edgeId);
246→  }, []);
247→
248→  // Canvas click → highlight only (no zoom)
249→  const handleBulkEditCanvasNodeClick = useCallback((nodeId: string) => {
250→    setBulkEditSelectedIds([]);
251→    setBulkEditFocusTarget(null);
252→    setBulkEditHighlightId(nodeId);
253→  }, []);
254→
255→  const handleBulkEditCanvasEdgeClick = useCallback((edgeId: string) => {
256→    setBulkEditSelectedIds([]);
257→    setBulkEditFocusTarget(null);
258→    setBulkEditHighlightId(edgeId);
259→  }, []);
260→
261→  const handleBulkEditSelectionChange = useCallback((selectedIds: string[]) => {
262→    setBulkEditSelectedIds(selectedIds);
263→    if (selectedIds.length > 0) {
264→      setBulkEditHighlightId(null);
265→      setBulkEditFocusTarget(null);
266→    }
267→  }, []);
268→
269→  const handleBulkEditPaneClick = useCallback(() => {
270→    setBulkEditSelectedIds([]);
271→    setBulkEditHighlightId(null);
272→    setBulkEditFocusTarget(null);
273→  }, []);
274→
275→  const diffStepRef = useRef(diffStep);
276→  diffStepRef.current = diffStep;
277→
278→  // --- Diff compare mode handlers ---
279→  const handleEnterDiffMode = useCallback(() => {
280→    setIsDiffMode(true);
281→    setDiffStep("import");
282→    setDiffBaseLayout(null);
283→    setDiffBaseFileName(null);
284→    setDiffBaseMeta(null);
285→    setDiffCompareLayout(null);
286→    setDiffCompareFileName(null);
287→    setDiffCompareMeta(null);
288→    setDiffResult(null);
289→    setDiffFilters(DEFAULT_DIFF_FILTERS);
290→  }, []);
291→
292→  const handleExitDiffMode = useCallback(() => {
293→    if (diffStepRef.current === "compare") {
294→      setDiffStep("import");
295→      setDiffResult(null);
296→    } else {
297→      setIsDiffMode(false);
298→    }
299→  }, []);
300→
301→  const handleDiffBaseSelect = useCallback((layout: FlowmaidLayout, fileName: string, meta: FileMeta) => {
302→    setDiffBaseLayout(layout);
303→    setDiffBaseFileName(fileName);
304→    setDiffBaseMeta(meta);
305→  }, []);
306→
307→  const handleDiffCompareSelect = useCallback((layout: FlowmaidLayout, fileName: string, meta: FileMeta) => {
308→    setDiffCompareLayout(layout);
309→    setDiffCompareFileName(fileName);
310→    setDiffCompareMeta(meta);
311→  }, []);
312→
313→  const handleDiffBaseClear = useCallback(() => {
314→    setDiffBaseLayout(null);
315→    setDiffBaseFileName(null);
316→    setDiffBaseMeta(null);
317→  }, []);
318→
319→  const handleDiffCompareClear = useCallback(() => {
320→    setDiffCompareLayout(null);
321→    setDiffCompareFileName(null);
322→    setDiffCompareMeta(null);
323→  }, []);
324→
325→  const handleRunDiff = useCallback(() => {
326→    if (diffBaseLayout && diffCompareLayout) {
327→      const result = computeDiff(diffBaseLayout, diffCompareLayout);
328→      setDiffResult(result);
329→      setDiffStep("compare");
330→    }
331→  }, [diffBaseLayout, diffCompareLayout]);
332→
333→  const handleDiffTextToggle = useCallback(() => {
334→    const panel = diffTextPanelRef.current;
335→    if (!panel) return;
336→    if (panel.isCollapsed()) {
337→      panel.expand();
338→      setDiffTextCollapsed(false);
339→    } else {
340→      panel.collapse();
341→      setDiffTextCollapsed(true);
342→    }
343→  }, []);
344→
345→  const handleDiffItemClick = useCallback((targetId: string, targetType: "node" | "edge") => {
346→    diffFlashSeqRef.current += 1;
347→    setDiffFlashTarget({ id: targetId, type: targetType, seq: diffFlashSeqRef.current });
348→  }, []);
349→
350→  return (
351→    <ReactFlowProvider>
352→      <DnDProvider>
353→        <div
354→          className="h-screen w-screen overflow-hidden flex flex-col transition-[padding,background-color] duration-500 ease-in-out"
355→          style={{
356→            padding: isEditingComponent ? '0.4% 1% 1% 1%' : '0',
357→            backgroundColor: isEditingComponent ? 'var(--foreground)' : 'transparent',
358→          }}
359→        >
360→          <div
361→            className="overflow-hidden transition-[max-height,opacity] duration-500 ease-in-out"
362→            style={{
363→              maxHeight: isEditingComponent ? '48px' : '0px',
364→              opacity: isEditingComponent ? 1 : 0,
365→            }}
366→          >
