 93→export function FlowCanvas({ gridSnap = false, ghostEnabled = true }: { gridSnap?: boolean; ghostEnabled?: boolean }) {
 94→  perfCount("FlowCanvas");
 95→  const nodes = useFlowStore((s) => s.nodes);
 96→  const edges = useFlowStore((s) => s.edges);
 97→  const onNodesChange = useFlowStore((s) => s.onNodesChange);
 98→  const onEdgesChange = useFlowStore((s) => s.onEdgesChange);
 99→  const addEdge = useFlowStore((s) => s.addEdge);
100→  const addNode = useFlowStore((s) => s.addNode);
101→  const reconnectEdge = useFlowStore((s) => s.reconnectEdge);
102→
103→  const placeComponentInstance = useFlowStore((s) => s.placeComponentInstance);
104→  const [dragPayload] = useDnDContext();
105→  const reactFlowInstance = useRef<ReactFlowInstance<FlowNode, FlowEdge> | null>(null);
106→  const { menu, open: openMenu, close: closeMenu } = useContextMenu();
107→  const { guides, onNodeDrag, applySnap, clearGuides } = useSnapGuides(nodes, gridSnap);
108→
109→  // Predictive input: compute all valid ghost nodes for all directions
110→  const addNodeWithData = useFlowStore((s) => s.addNodeWithData);
111→  const DIRECTIONS: PredictiveDirection[] = useMemo(() => ["top", "right", "bottom", "left"], []);
112→  const OVERLAP_MARGIN = 10;
113→
114→  // Global candidate index for Tab cycling (applies to all visible ghosts)
115→  const [ghostCandidateIndex, setGhostCandidateIndex] = useState(0);
116→  const isDraggingRef = useRef(false);
117→
118→  // Cache candidates per source node (for Tab cycling)
119→  const candidatesMap = useMemo(() => {
120→    const map: Record<string, ReturnType<typeof computeCandidates>> = {};
121→    for (const node of nodes) {
122→      if (node.id.startsWith(GHOST_NODE_ID)) continue;
123→      if (node.data.componentParentId) continue;
124→      map[node.id] = computeCandidates(node, edges, nodes);
125→    }
126→    return map;
127→  }, [nodes, edges]);
128→
129→  const allGhosts = useMemo(() => {
130→    const ghostNodes: FlowNode[] = [];
131→    const ghostEdges: FlowEdge[] = [];
132→
133→    // Hide ghosts when disabled or while dragging
134→    if (!ghostEnabled || isDraggingRef.current) return { ghostNodes, ghostEdges };
135→
136→    // Show ghosts only when exactly one node is selected (exclude text nodes — used as memos)
137→    const selectedNodes = nodes.filter((n) => n.selected && !n.id.startsWith(GHOST_NODE_ID) && !n.data.componentParentId && n.data.shape !== "text");
138→    const selectedNode = selectedNodes.length === 1 ? selectedNodes[0] : undefined;
139→    if (selectedNode) {
140→      const node = selectedNode;
141→      const candidates = candidatesMap[node.id];
142→      if (!candidates || candidates.length === 0) return { ghostNodes, ghostEdges };
143→
144→      for (const dir of DIRECTIONS) {
145→        // Component instances: only show ghosts in the component's flow direction
146→        if (node.data.componentDefinitionId) {
147→          const compDir = (node.data.componentDefinitionDirection as string) ?? "TD";
148→          if (compDir === "TD" && (dir === "left" || dir === "right")) continue;
149→          if (compDir === "LR" && (dir === "top" || dir === "bottom")) continue;
150→        }
151→
152→        // Pick candidate: use global cycled index for all ghosts
153→        const ghostKey = `${node.id}_${dir}`;
154→        const candIdx = ((ghostCandidateIndex % candidates.length) + candidates.length) % candidates.length;
155→        const candidate = candidates[candIdx];
156→
157→        // Skip if edge already connected in this direction
158→        const hasEdge = edges.some((e) => {
159→          if (e.data?.isBridgeEdge) return false;
160→          return (e.source === node.id && e.sourceHandle === `${dir}-source`) ||
161→                 (e.target === node.id && e.targetHandle === `${dir}-target`);
162→        });
163→        if (hasEdge) continue;
164→
165→        // Compute ghost position
166→        const ghostPos = computeGhostPosition(node, dir, candidate.nodeData.shape);
167→
168→        // Skip if overlapping existing node
169→        const hasOverlap = nodes.some((other) => {
170→          if (other.id === node.id || other.id.startsWith(GHOST_NODE_ID)) return false;
171→          if (other.data.componentParentId) return false;
172→          const ow = other.measured?.width ?? (other.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
173→          const oh = other.measured?.height ?? (other.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
174→          return ghostPos.x < other.position.x + ow - OVERLAP_MARGIN &&
175→                 ghostPos.x + ghostPos.gw > other.position.x + OVERLAP_MARGIN &&
176→                 ghostPos.y < other.position.y + oh - OVERLAP_MARGIN &&
177→                 ghostPos.y + ghostPos.gh > other.position.y + OVERLAP_MARGIN;
178→        });
179→        if (hasOverlap) continue;
180→
181→        const ghostId = `${GHOST_NODE_ID}${ghostKey}`;
182→        const handles = DIRECTION_HANDLES[dir];
183→        const ghostSize = getGhostSize(node, candidate.nodeData.shape);
184→
185→        ghostNodes.push({
186→          id: ghostId,
187→          type: candidate.nodeData.shape,
188→          position: { x: ghostPos.x, y: ghostPos.y },
189→          width: ghostSize.width,
190→          height: ghostSize.height,
191→          data: {
192→            ...candidate.nodeData,
193→            label: "...",
194→            ghostTargetHandle: handles.targetHandle,
195→            ghostSourceNodeId: node.id,
196→            ghostDirection: dir,
197→            ghostCandidateIndex: candIdx,
198→          },
199→          style: { width: ghostSize.width, height: ghostSize.height },
200→          selectable: false,
201→          draggable: false,
202→        });
203→
204→        ghostEdges.push({
205→          id: `__ghost_edge__${ghostKey}`,
206→          source: node.id,
207→          target: ghostId,
208→          sourceHandle: handles.sourceHandle,
209→          targetHandle: handles.targetHandle,
210→          type: "labeled",
211→          style: { strokeDasharray: "6 3" },
212→          selectable: false,
213→          markerEnd: { type: MarkerType.ArrowClosed },
214→          data: {
215→            edgeType: candidate.edgeData?.edgeType ?? "bezier",
216→            markerEnd: candidate.edgeData?.markerEnd ?? "arrowclosed",
217→            markerStart: candidate.edgeData?.markerStart,
218→            strokeStyle: "dashed",
219→          },
220→        } as FlowEdge);
221→      }
222→    }
223→
224→    return { ghostNodes, ghostEdges };
225→  }, [nodes, edges, DIRECTIONS, OVERLAP_MARGIN, candidatesMap, ghostCandidateIndex, ghostEnabled]);
226→
227→  const hasGhosts = allGhosts.ghostNodes.length > 0;
228→
229→  // Inject ghost nodes/edges into arrays for rendering
230→  const nodesWithGhost = useMemo(
231→    () => allGhosts.ghostNodes.length > 0 ? [...nodes, ...allGhosts.ghostNodes] : nodes,
232→    [nodes, allGhosts.ghostNodes],
233→  );
234→  const edgesWithGhost = useMemo(
235→    () => allGhosts.ghostEdges.length > 0 ? [...edges, ...allGhosts.ghostEdges] : edges,
236→    [edges, allGhosts.ghostEdges],
237→  );
238→
239→  // Minimap toggle (persisted in localStorage, default: hidden)
240→  const [showMinimap, setShowMinimap] = useState(() => {
241→    if (typeof window === "undefined") return false;
242→    return localStorage.getItem(MINIMAP_STORAGE_KEY) === "true";
243→  });
244→  const toggleMinimap = useCallback(() => {
245→    setShowMinimap((prev) => {
246→      const next = !prev;
247→      localStorage.setItem(MINIMAP_STORAGE_KEY, String(next));
248→      return next;
249→    });
250→  }, []);

