 45→function inferTargetPosition(sourceX: number, sourceY: number, targetX: number, targetY: number): Position {
 46→  const dx = targetX - sourceX;
 47→  const dy = targetY - sourceY;
 48→  if (Math.abs(dx) > Math.abs(dy)) {
 49→    return dx > 0 ? Position.Left : Position.Right;
 50→  }
