const SHAPE_KEYS: { type: string; key: TranslationKey }[] = [
  { type: "rectangle", key: "rectangle" },
  { type: "roundedRect", key: "roundedRect" },
  { type: "diamond", key: "diamond" },
  { type: "circle", key: "circle" },
  { type: "stadium", key: "stadium" },
  { type: "parallelogram", key: "parallelogram" },
  { type: "cylinder", key: "cylinder" },
  { type: "hexagon", key: "hexagon" },
  { type: "trapezoid", key: "trapezoid" },
];

interface ToolbarProps {
  onExport?: () => void;
  onImport?: () => void;
  onImportMermaid?: () => void;
  onFitView?: () => void;
  isBulkEditMode?: boolean;
  onEnterBulkEdit?: () => void;
  onExitBulkEdit?: () => void;
  isDiffMode?: boolean;
  onEnterDiffMode?: () => void;
  onExitDiffMode?: () => void;
  /** Rendered in the toolbar's right area when in diff compare mode */
  diffFilterBar?: React.ReactNode;
  gridSnap?: boolean;
  onToggleGridSnap?: () => void;
  ghostEnabled?: boolean;
  onToggleGhost?: () => void;
}

export function Toolbar({ onExport, onImport, onImportMermaid, onFitView, isBulkEditMode, onEnterBulkEdit, onExitBulkEdit, isDiffMode, onEnterDiffMode, onExitDiffMode, diffFilterBar, gridSnap, onToggleGridSnap, ghostEnabled, onToggleGhost }: ToolbarProps) {
  const { theme, setTheme } = useTheme();
  const { undo, redo, canUndo, canRedo } = useUndoRedo();
  const direction = useFlowStore((s) => s.direction);
  const setDirection = useFlowStore((s) => s.setDirection);
  const addNode = useFlowStore((s) => s.addNode);
  const clearAll = useFlowStore((s) => s.clearAll);
  const hasContent = useFlowStore((s) => s.nodes.length > 0 || s.edges.length > 0);
  const { locale, setLocale, t } = useLocale();

  return (
    <div className="flex items-center gap-1 px-3 py-1.5 border-b border-border bg-background">
      <span className="font-semibold text-sm mr-2">Flowmaid</span>

      {!isDiffMode && (
        <>
          <Separator orientation="vertical" className="h-6" />

          <DropdownMenu>
            <Tooltip>
              <TooltipTrigger asChild>
                <DropdownMenuTrigger asChild>
                  <Button variant="ghost" size="icon" className="h-8 w-8">
                    <Plus size={16} />
                  </Button>
                </DropdownMenuTrigger>
              </TooltipTrigger>
              <TooltipContent>{t("addNode")}</TooltipContent>
            </Tooltip>
            <DropdownMenuContent>
              {SHAPE_KEYS.map(({ type, key }) => (
                <DropdownMenuItem key={type} onClick={() => addNode(type)}>
                  {t(key)}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>

          <Separator orientation="vertical" className="h-6" />

          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8"
                onClick={undo}
                disabled={!canUndo}
              >
                <Undo2 size={16} />
              </Button>
            </TooltipTrigger>
            <TooltipContent>{t("undo")}</TooltipContent>
          </Tooltip>

          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8"
                onClick={redo}
                disabled={!canRedo}
              >
                <Redo2 size={16} />
              </Button>
            </TooltipTrigger>
            <TooltipContent>{t("redo")}</TooltipContent>
          </Tooltip>

          <Separator orientation="vertical" className="h-6" />

          <ToggleGroup
            type="single"
            value={direction}
            onValueChange={(val) => {
              if (val) setDirection(val as FlowDirection);
            }}
            className="h-8"
          >
            <ToggleGroupItem value="TD" className="h-8 px-2 text-xs">
              {t("dirTD")}
            </ToggleGroupItem>
            <ToggleGroupItem value="LR" className="h-8 px-2 text-xs">
              {t("dirLR")}
            </ToggleGroupItem>
          </ToggleGroup>

          <Separator orientation="vertical" className="h-6" />

          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant={gridSnap ? "secondary" : "ghost"}
                size="icon"
                className="h-8 w-8"
                onClick={onToggleGridSnap}
              >
                <Grid3x3 size={16} />
              </Button>
            </TooltipTrigger>
            <TooltipContent>{t("snapToGrid")}</TooltipContent>
          </Tooltip>

          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant={ghostEnabled ? "secondary" : "ghost"}
                size="icon"
                className="h-8 w-8"
                onClick={onToggleGhost}
              >
                <SquareDashed size={16} />
              </Button>
            </TooltipTrigger>
            <TooltipContent>{t("ghostNodes")}</TooltipContent>
          </Tooltip>
        </>
      )}

      <div className="flex-1" />

      {onEnterBulkEdit && !isBulkEditMode && !isDiffMode && (
        <Button
          variant="outline"
          size="sm"
          className="h-7 gap-1.5 text-xs px-3"
          onClick={onEnterBulkEdit}
          disabled={!hasContent}
        >
          <Table2 size={14} />
          {t("bulkEdit")}
        </Button>
      )}

      {onEnterDiffMode && !isBulkEditMode && !isDiffMode && (
        <Button
          variant="outline"
          size="sm"
          className="h-7 gap-1.5 text-xs px-3 ml-1"
          onClick={onEnterDiffMode}
        >
          <GitCompareArrows size={14} />
          {t("diffCompare")}
        </Button>
      )}

      {isDiffMode && diffFilterBar}

      <div className="flex-1" />

      {onExport && (
        <Tooltip>
          <TooltipTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8"
              onClick={onExport}
            >
              <Upload size={16} />
            </Button>
          </TooltipTrigger>
          <TooltipContent>{t("exportFile")}</TooltipContent>
        </Tooltip>
      )}

      {onImport && (
        <Tooltip>
          <TooltipTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8"
              onClick={onImport}
            >
              <Download size={16} />
            </Button>
          </TooltipTrigger>
          <TooltipContent>{t("importFile")}</TooltipContent>
        </Tooltip>
      )}

      {onImportMermaid && (
        <Tooltip>
          <TooltipTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8"
              onClick={onImportMermaid}
            >
              <FileCode2 size={16} />
            </Button>
          </TooltipTrigger>
          <TooltipContent>{t("importMermaid")}</TooltipContent>
        </Tooltip>
      )}

      {!isDiffMode && (
        <>
          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8"
                disabled={!hasContent}
                onClick={() => {
                  if (window.confirm(t("clearAllConfirm"))) clearAll();
                }}
              >
                <Trash2 size={16} />
              </Button>
            </TooltipTrigger>
            <TooltipContent>{t("clearAll")}</TooltipContent>
          </Tooltip>

          <Separator orientation="vertical" className="h-6" />
        </>
      )}

      <Tooltip>
        <TooltipTrigger asChild>
          <Button
            variant="ghost"
            size="icon"
            className="h-8 w-8"
            onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
          >
            {theme === "dark" ? <Sun size={16} /> : <Moon size={16} />}
          </Button>
        </TooltipTrigger>
        <TooltipContent>{t("toggleTheme")}</TooltipContent>
      </Tooltip>

      <Tooltip>
        <TooltipTrigger asChild>
          <Button
            variant="ghost"
            className="h-8 px-2 text-xs font-semibold"
            onClick={() => setLocale(locale === "ja" ? "en" : "ja")}
          >
            {locale === "ja" ? "JP" : "EN"}
          </Button>
        </TooltipTrigger>
        <TooltipContent>{locale === "ja" ? "English" : "日本語"}</TooltipContent>
      </Tooltip>
    </div>
  );
}

