  1→"use client";
  2→
  3→import { useEffect, useRef } from "react";
  4→import { useUndoRedo } from "./useUndoRedo";
  5→import { useFlowStore } from "@/store/useFlowStore";
  6→import type { FlowNode, FlowEdge } from "@/store/types";
  7→import { counterToId } from "@/lib/id";
  8→
  9→interface ClipboardData {
 10→  nodes: FlowNode[];
 11→  edges: FlowEdge[];
 12→}
 13→
 14→let clipboard: ClipboardData | null = null;
 15→
 16→export function useKeyboardShortcuts() {
 17→  const { undo, redo } = useUndoRedo();
 18→  const storeRef = useRef(useFlowStore);
 19→
 20→  useEffect(() => {
 21→    const handler = (e: KeyboardEvent) => {
 22→      // Skip if user is typing in an input/textarea
 23→      const tag = (e.target as HTMLElement)?.tagName;
 24→      if (tag === "INPUT" || tag === "TEXTAREA") return;
 25→
 26→      const isCtrl = e.ctrlKey || e.metaKey;
 27→
 28→      if (isCtrl && e.key === "z" && !e.shiftKey) {
 29→        e.preventDefault();
 30→        undo();
 31→      }
 32→
 33→      if (isCtrl && e.key === "z" && e.shiftKey) {
 34→        e.preventDefault();
 35→        redo();
 36→      }
 37→
 38→      if (isCtrl && e.key === "Z") {
 39→        e.preventDefault();
 40→        redo();
 41→      }
 42→
 43→      if (isCtrl && e.key === "s") {
 44→        e.preventDefault();
 45→        window.dispatchEvent(new CustomEvent("flowmaid:export"));
 46→      }
 47→
 48→      // F2 to start editing selected node/edge label
 49→      if (e.key === "F2") {
 50→        e.preventDefault();
 51→        const state = storeRef.current.getState();
 52→        const selectedNodes = state.nodes.filter((n) => n.selected);
 53→        const selectedEdges = state.edges.filter((edge) => edge.selected);
 54→        if (selectedNodes.length === 1) {
 55→          const node = selectedNodes[0];
 56→          if (!node.data?.isLocked) {
 57→            window.dispatchEvent(
 58→              new CustomEvent("flowmaid:startEdit", { detail: { type: "node", id: node.id } })
 59→            );
 60→          }
 61→        } else if (selectedEdges.length === 1) {
 62→          window.dispatchEvent(
 63→            new CustomEvent("flowmaid:startEdit", { detail: { type: "edge", id: selectedEdges[0].id } })
 64→          );
 65→        }
 66→      }
 67→
 68→      // Select all nodes and edges
 69→      if (isCtrl && e.key === "a") {
 70→        e.preventDefault();
 71→        const state = storeRef.current.getState();
 72→        storeRef.current.setState({
 73→          nodes: state.nodes.map((n) => ({ ...n, selected: true })),
 74→          edges: state.edges.map((edge) => ({ ...edge, selected: true })),
 75→        });
 76→      }
 77→
 78→      // Copy selected nodes
 79→      if (isCtrl && e.key === "c") {
 80→        const state = storeRef.current.getState();
 81→        const selectedNodes = state.nodes.filter((n) => n.selected);
 82→        if (selectedNodes.length === 0) return;
 83→        const nodeIds = new Set(selectedNodes.map((n) => n.id));
 84→        const relatedEdges = state.edges.filter(
 85→          (edge) => nodeIds.has(edge.source) && nodeIds.has(edge.target)
 86→        );
 87→        clipboard = { nodes: selectedNodes, edges: relatedEdges };
 88→      }
 89→
 90→      // Paste
 91→      if (isCtrl && e.key === "v") {
 92→        if (!clipboard || clipboard.nodes.length === 0) return;
 93→        e.preventDefault();
 94→        const state = storeRef.current.getState();
 95→        let counter = state.nextIdCounter;
 96→        const idMap = new Map<string, string>();
 97→
 98→        const newNodes: FlowNode[] = clipboard.nodes.map((n) => {
 99→          const newId = counterToId(counter++);
100→          idMap.set(n.id, newId);
101→          return {
102→            ...n,
103→            id: newId,
104→            position: { x: n.position.x + 30, y: n.position.y + 30 },
105→            data: { ...n.data },
106→            selected: true,
107→          };
108→        });
109→
110→        const newEdges: FlowEdge[] = clipboard.edges.map((edge) => {
111→          const newSource = idMap.get(edge.source) ?? edge.source;
112→          const newTarget = idMap.get(edge.target) ?? edge.target;
113→          return {
114→            ...edge,
115→            id: `${newSource}-${newTarget}-${edge.sourceHandle ?? "d"}-${edge.targetHandle ?? "d"}`,
116→            source: newSource,
117→            target: newTarget,
118→            selected: false,
119→          };
120→        });
121→
122→        // Deselect existing nodes
123→        const deselectedNodes = state.nodes.map((n) => ({ ...n, selected: false }));
124→
125→        storeRef.current.setState({
126→          nodes: [...deselectedNodes, ...newNodes],
127→          edges: [...state.edges, ...newEdges],
128→          nextIdCounter: counter,
129→        });
130→      }
131→    };
132→
133→    window.addEventListener("keydown", handler);
134→    return () => window.removeEventListener("keydown", handler);
135→  }, [undo, redo]);
136→}
