  1→"use client";
  2→
  3→import { useState, useRef, useEffect, useCallback } from "react";
  4→import { useFlowStore } from "@/store/useFlowStore";
  5→import { useLocale } from "@/lib/i18n/useLocale";
  6→import type { TextAlign } from "@/types/flow";
  7→
  8→interface NodeLabelProps {
  9→  id: string;
 10→  label: string;
 11→  fontSize?: number;
 12→  textColor?: string;
 13→  textAlign?: TextAlign;
 14→  bold?: boolean;
 15→  italic?: boolean;
 16→  underline?: boolean;
 17→  isLocked?: boolean;
 18→}
 19→
 20→export function NodeLabel({
 21→  id,
 22→  label,
 23→  fontSize,
 24→  textColor,
 25→  textAlign,
 26→  bold,
 27→  italic,
 28→  underline,
 29→  isLocked,
 30→}: NodeLabelProps) {
 31→  const { t } = useLocale();
 32→  const [editing, setEditing] = useState(false);
 33→  const [value, setValue] = useState(label);
 34→  const textareaRef = useRef<HTMLTextAreaElement>(null);
 35→  const updateNodeLabel = useFlowStore((s) => s.updateNodeLabel);
 36→
 37→  useEffect(() => {
 38→    setValue(label);
 39→  }, [label]);
 40→
 41→  useEffect(() => {
 42→    const handler = (e: Event) => {
 43→      const detail = (e as CustomEvent).detail;
 44→      if (detail?.type === "node" && detail?.id === id && !isLocked) {
 45→        setEditing(true);
 46→      }
 47→    };
 48→    window.addEventListener("flowmaid:startEdit", handler);
 49→    return () => window.removeEventListener("flowmaid:startEdit", handler);
 50→  }, [id, isLocked]);
 51→
 52→  useEffect(() => {
 53→    if (editing && textareaRef.current) {
 54→      textareaRef.current.focus();
 55→      textareaRef.current.select();
 56→      autoResize(textareaRef.current);
 57→    }
 58→  }, [editing]);
 59→
 60→  const autoResize = (el: HTMLTextAreaElement) => {
 61→    el.style.height = "auto";
 62→    el.style.height = el.scrollHeight + "px";
 63→  };
 64→
 65→  const commit = useCallback(() => {
 66→    setEditing(false);
 67→    const trimmed = value.trim();
 68→    if (trimmed && trimmed !== label) {
 69→      updateNodeLabel(id, trimmed);
 70→    } else {
 71→      setValue(label);
 72→    }
 73→  }, [value, label, id, updateNodeLabel]);
 74→
 75→  const textStyle: React.CSSProperties = {
 76→    fontSize: fontSize ? `${fontSize}px` : undefined,
 77→    color: textColor || undefined,
 78→    textAlign: textAlign || "center",
 79→    fontWeight: bold ? "bold" : undefined,
 80→    fontStyle: italic ? "italic" : undefined,
 81→    textDecoration: underline ? "underline" : undefined,
 82→  };
 83→
 84→  if (editing) {
 85→    return (
 86→      <>
 87→        <textarea
 88→          ref={textareaRef}
 89→          className="nodrag nowheel bg-transparent text-sm outline-none border-b border-foreground/30 w-full resize-none overflow-hidden"
 90→          style={textStyle}
 91→          value={value}
 92→          rows={1}
 93→          onChange={(e) => {
 94→            setValue(e.target.value);
 95→            autoResize(e.target);
 96→          }}
 97→          onBlur={commit}
 98→          onKeyDown={(e) => {
 99→            if (e.key === "Enter" && !e.shiftKey) {
100→              commit();
101→            }
102→            if (e.key === "Escape") {
103→              setValue(label);
104→              setEditing(false);
105→            }
106→          }}
107→        />
108→        <span
109→          className="absolute left-0 w-full text-[9px] text-muted-foreground/60 pointer-events-none"
110→          style={{ top: "100%", textAlign: "center", marginTop: 4 }}
111→        >
112→          {t("newlineHint")}
113→        </span>
114→      </>
115→    );
116→  }
117→
118→  const hasNewlines = label.includes("\n");
119→
120→  return (
121→    <span
122→      className="node-label-text select-none max-w-full w-full"
123→      style={textStyle}
124→      draggable={false}
125→      onDoubleClick={() => !isLocked && setEditing(true)}
126→    >
127→      {hasNewlines
128→        ? label.split("\n").map((line, i) => (
129→            <span key={i}>
130→              {i > 0 && <br />}
131→              {line}
132→            </span>
133→          ))
134→        : label}
135→    </span>
136→  );
137→}
