  1→"use client";
  2→
  3→import { memo, useState, useRef, useEffect, useCallback } from "react";
  4→import { perfCount } from "@/lib/perf";
  5→import {
  6→  EdgeLabelRenderer,
  7→  getBezierPath,
  8→  getStraightPath,
  9→  getSmoothStepPath,
 10→  Position,
 11→  useReactFlow,
 12→  type EdgeProps,
 13→} from "@xyflow/react";
 14→import { useFlowStore } from "@/store/useFlowStore";
 15→import type { FlowEdge } from "@/store/types";
 16→import { computeColor } from "@/lib/color";
 17→import type { Waypoint } from "@/types/flow";
 18→
 19→const WAYPOINT_BORDER_RADIUS = 8;
 20→
 21→function buildWaypointPath(
 22→  sx: number, sy: number,
 23→  tx: number, ty: number,
 24→  waypoints: Waypoint[],
 25→  borderRadius: number = WAYPOINT_BORDER_RADIUS,
 26→): string {
 27→  const pts: Waypoint[] = [{ x: sx, y: sy }, ...waypoints, { x: tx, y: ty }];
 28→  if (pts.length < 2) return "";
 29→  if (pts.length === 2 || borderRadius <= 0) {
 30→    let d = `M ${pts[0].x} ${pts[0].y}`;
 31→    for (let i = 1; i < pts.length; i++) {
 32→      d += ` L ${pts[i].x} ${pts[i].y}`;
 33→    }
 34→    return d;
 35→  }
 36→
 37→  let d = `M ${pts[0].x} ${pts[0].y}`;
 38→  for (let i = 1; i < pts.length - 1; i++) {
 39→    const prev = pts[i - 1];
 40→    const curr = pts[i];
 41→    const next = pts[i + 1];
 42→
 43→    // Vector from curr to prev / next
 44→    const dxIn = prev.x - curr.x;
 45→    const dyIn = prev.y - curr.y;
 46→    const dxOut = next.x - curr.x;
 47→    const dyOut = next.y - curr.y;
 48→
 49→    const lenIn = Math.hypot(dxIn, dyIn);
 50→    const lenOut = Math.hypot(dxOut, dyOut);
 51→
 52→    // Clamp radius so it doesn't exceed half of either segment
 53→    const r = Math.min(borderRadius, lenIn / 2, lenOut / 2);
 54→
 55→    if (r < 1) {
 56→      d += ` L ${curr.x} ${curr.y}`;
 57→      continue;
 58→    }
 59→
 60→    // Points where the arc starts and ends
 61→    const startX = curr.x + (dxIn / lenIn) * r;
 62→    const startY = curr.y + (dyIn / lenIn) * r;
 63→    const endX = curr.x + (dxOut / lenOut) * r;
 64→    const endY = curr.y + (dyOut / lenOut) * r;
 65→
 66→    d += ` L ${startX} ${startY}`;
 67→    d += ` Q ${curr.x} ${curr.y} ${endX} ${endY}`;
 68→  }
 69→  d += ` L ${pts[pts.length - 1].x} ${pts[pts.length - 1].y}`;
 70→  return d;
 71→}
 72→
 73→const DETOUR_OFFSET = 50;
 74→
 75→/** Calculate midpoint with U-shaped detour for same-direction handles */
 76→function computeMid(
 77→  s: number, t: number,
 78→  sPos: Position, tPos: Position,
 79→  positivePos: Position,
 80→): number {
 81→  const sGoesPositive = sPos === positivePos;
 82→  const tGoesPositive = tPos === positivePos;
 83→
 84→  if (sGoesPositive !== tGoesPositive) {
 85→    // Opposite-direction handles (Bottom→Top, Left→Right, etc.)
 86→    // midpoint always between source and target → arrow direction preserved
 87→    return Math.round((s + t) / 2);
 88→  }
 89→
 90→  // Same-direction handles (Bottom→Bottom, Top→Top, etc.) → U-shaped detour
 91→  if (sGoesPositive) {
 92→    return Math.round(Math.max(s, t) + DETOUR_OFFSET);
 93→  } else {
 94→    return Math.round(Math.min(s, t) - DETOUR_OFFSET);
 95→  }
 96→}
 97→
 98→function computeStepCorners(
 99→  sx: number, sy: number, sPos: Position,
100→  tx: number, ty: number, tPos: Position,
101→): Waypoint[] {
102→  const isSourceVertical = sPos === Position.Top || sPos === Position.Bottom;
103→  const isTargetVertical = tPos === Position.Top || tPos === Position.Bottom;
104→
105→  if (isSourceVertical && isTargetVertical) {
106→    const midY = computeMid(sy, ty, sPos, tPos, Position.Bottom);
107→    if (Math.abs(sx - tx) < 1) return [];
108→    return [
109→      { x: Math.round(sx), y: midY },
110→      { x: Math.round(tx), y: midY },
111→    ];
112→  } else if (!isSourceVertical && !isTargetVertical) {
113→    const midX = computeMid(sx, tx, sPos, tPos, Position.Right);
114→    if (Math.abs(sy - ty) < 1) return [];
115→    return [
116→      { x: midX, y: Math.round(sy) },
117→      { x: midX, y: Math.round(ty) },
118→    ];
119→  } else if (isSourceVertical && !isTargetVertical) {
120→    return [
121→      { x: Math.round(sx), y: Math.round(ty) },
122→    ];
123→  } else {
124→    return [
125→      { x: Math.round(tx), y: Math.round(sy) },
126→    ];
127→  }
128→}
129→
130→const NODE_AVOID_MARGIN = 20;
131→
132→interface NodeRect { x: number; y: number; w: number; h: number }
133→
134→/** Check if an axis-aligned segment overlaps a rectangle (with margin) */
135→function segOverlapsRect(
136→  ax: number, ay: number, bx: number, by: number,
137→  r: NodeRect, m: number,
138→): boolean {
139→  const left = r.x - m, right = r.x + r.w + m;
140→  const top = r.y - m, bottom = r.y + r.h + m;
141→  const minX = Math.min(ax, bx), maxX = Math.max(ax, bx);
142→  const minY = Math.min(ay, by), maxY = Math.max(ay, by);
143→  return maxX > left && minX < right && maxY > top && minY < bottom;
144→}
145→
146→/** Get bounding rects of all top-level visible nodes except source/target */
147→function getObstacleRects(sourceId: string, targetId: string): NodeRect[] {
148→  const nodes = useFlowStore.getState().nodes;
149→  return nodes
150→    .filter(n => n.id !== sourceId && n.id !== targetId && !n.hidden && !n.parentId)
151→    .map(n => ({
152→      x: n.position.x,
153→      y: n.position.y,
154→      w: (n.style?.width as number) ?? (n.measured?.width as number) ?? 150,
155→      h: (n.style?.height as number) ?? (n.measured?.height as number) ?? 50,
156→    }));
157→}
158→
159→/**
160→ * Compute step corners with node-avoidance: shifts the connecting segment
161→ * (midY for both-vertical, midX for both-horizontal) so it doesn't pass through nodes.
162→ */
163→function computeStepCornersAvoidingNodes(
164→  sx: number, sy: number, sPos: Position,
165→  tx: number, ty: number, tPos: Position,
166→  sourceId: string, targetId: string,
167→): Waypoint[] {
168→  const basic = computeStepCorners(sx, sy, sPos, tx, ty, tPos);
169→  if (basic.length !== 2) return basic; // only adjust 2-corner paths
170→
171→  const rects = getObstacleRects(sourceId, targetId);
172→  if (rects.length === 0) return basic;
173→
174→  const isSourceVertical = sPos === Position.Top || sPos === Position.Bottom;
175→  const isTargetVertical = tPos === Position.Top || tPos === Position.Bottom;
176→  const m = NODE_AVOID_MARGIN;
177→
178→  if (isSourceVertical && isTargetVertical) {
179→    // Horizontal connecting segment at midY
180→    let midY = basic[0].y;
181→    for (let iter = 0; iter < 5; iter++) {
182→      const blocked = rects.filter(r =>
183→        segOverlapsRect(Math.min(sx, tx), midY, Math.max(sx, tx), midY, r, m)
184→      );
185→      if (blocked.length === 0) break;
186→      let minTop = Infinity, maxBottom = -Infinity;
187→      for (const r of blocked) {
188→        minTop = Math.min(minTop, r.y - m);
189→        maxBottom = Math.max(maxBottom, r.y + r.h + m);
190→      }
191→      const above = Math.round(minTop);
192→      const below = Math.round(maxBottom);
193→      midY = Math.abs(midY - above) <= Math.abs(midY - below) ? above : below;
194→    }
195→    return [{ x: Math.round(sx), y: midY }, { x: Math.round(tx), y: midY }];
196→  } else if (!isSourceVertical && !isTargetVertical) {
197→    // Vertical connecting segment at midX
198→    let midX = basic[0].x;
199→    for (let iter = 0; iter < 5; iter++) {
200→      const blocked = rects.filter(r =>
201→        segOverlapsRect(midX, Math.min(sy, ty), midX, Math.max(sy, ty), r, m)
202→      );
203→      if (blocked.length === 0) break;
204→      let minLeft = Infinity, maxRight = -Infinity;
205→      for (const r of blocked) {
206→        minLeft = Math.min(minLeft, r.x - m);
207→        maxRight = Math.max(maxRight, r.x + r.w + m);
208→      }
209→      const left = Math.round(minLeft);
210→      const right = Math.round(maxRight);
211→      midX = Math.abs(midX - left) <= Math.abs(midX - right) ? left : right;
212→    }
213→    return [{ x: midX, y: Math.round(sy) }, { x: midX, y: Math.round(ty) }];
214→  }
215→
216→  return basic;
217→}
218→
219→/** Determine which segment index a click position is closest to */
220→function findClosestSegment(allPts: Waypoint[], clickPos: Waypoint): number {
221→  let bestIdx = 0;
222→  let bestDist = Infinity;
223→  for (let i = 0; i < allPts.length - 1; i++) {
224→    // Distance from point to line segment
225→    const a = allPts[i];
226→    const b = allPts[i + 1];
227→    const dx = b.x - a.x;
228→    const dy = b.y - a.y;
229→    const len2 = dx * dx + dy * dy;
230→    let t = len2 === 0 ? 0 : Math.max(0, Math.min(1, ((clickPos.x - a.x) * dx + (clickPos.y - a.y) * dy) / len2));
231→    const px = a.x + t * dx;
232→    const py = a.y + t * dy;
233→    const dist = Math.hypot(clickPos.x - px, clickPos.y - py);
234→    if (dist < bestDist) {
235→      bestDist = dist;
236→      bestIdx = i;
237→    }
238→  }
239→  return bestIdx;
240→}
