242→export const LabeledEdge = memo(function LabeledEdge({
243→  id,
244→  source,
245→  target,
246→  sourceX,
247→  sourceY,
248→  targetX,
249→  targetY,
250→  sourcePosition,
251→  targetPosition,
252→  style,
253→  data,
254→  selected,
255→  markerEnd,
256→  markerStart,
257→}: EdgeProps<FlowEdge>) {
258→  perfCount("LabeledEdge");
259→  const edgeType = data?.edgeType ?? "bezier";
260→  const waypoints = data?.waypoints ?? [];
261→  const hasWaypoints = waypoints.length > 0;
262→
263→  const pathParams = { sourceX, sourceY, sourcePosition, targetX, targetY, targetPosition };
264→  let edgePath: string;
265→  let labelX: number;
266→  let labelY: number;
267→
268→  if (hasWaypoints) {
269→    edgePath = buildWaypointPath(sourceX, sourceY, targetX, targetY, waypoints);
270→    const allPts: Waypoint[] = [{ x: sourceX, y: sourceY }, ...waypoints, { x: targetX, y: targetY }];
271→    const midSegIdx = Math.floor((allPts.length - 1) / 2);
272→    const a = allPts[midSegIdx];
273→    const b = allPts[midSegIdx + 1];
274→    labelX = (a.x + b.x) / 2;
275→    labelY = (a.y + b.y) / 2 - 16;
276→  } else if (edgeType === "straight") {
277→    [edgePath, labelX, labelY] = getStraightPath(pathParams);
278→  } else if (edgeType === "step") {
279→    [edgePath, labelX, labelY] = getSmoothStepPath({ ...pathParams, borderRadius: 8 });
280→  } else {
281→    [edgePath, labelX, labelY] = getBezierPath(pathParams);
282→  }
283→
284→  const updateEdgeWaypoints = useFlowStore((s) => s.updateEdgeWaypoints);
285→
286→  // Auto-generate waypoints when switching to step with no existing waypoints
287→  const prevEdgeTypeRef = useRef(edgeType);
288→  useEffect(() => {
289→    if (edgeType === "step" && prevEdgeTypeRef.current !== "step" && waypoints.length === 0) {
290→      const corners = computeStepCornersAvoidingNodes(sourceX, sourceY, sourcePosition, targetX, targetY, targetPosition, source, target);
291→      if (corners.length > 0) {
292→        updateEdgeWaypoints(id, corners);
293→      }
294→    }
295→    prevEdgeTypeRef.current = edgeType;
296→  }, [edgeType]); // eslint-disable-line react-hooks/exhaustive-deps
297→
298→  // Track node movement and adjust waypoints to maintain right-angle segments
299→  const prevPosRef = useRef({ sx: sourceX, sy: sourceY, tx: targetX, ty: targetY });
300→  useEffect(() => {
301→    const prev = prevPosRef.current;
302→    const sdx = sourceX - prev.sx;
303→    const sdy = sourceY - prev.sy;
304→    const tdx = targetX - prev.tx;
305→    const tdy = targetY - prev.ty;
306→    prevPosRef.current = { sx: sourceX, sy: sourceY, tx: targetX, ty: targetY };
307→
308→    if ((sdx === 0 && sdy === 0 && tdx === 0 && tdy === 0) || waypoints.length === 0) return;
309→
310→    if (waypoints.length <= 2) {
311→      // Basic step edge (auto-generated): recalculate from scratch to avoid broken paths
312→      const corners = computeStepCornersAvoidingNodes(sourceX, sourceY, sourcePosition, targetX, targetY, targetPosition, source, target);
313→      if (corners.length === 0) {
314→        // Nodes are aligned — clear waypoints
315→        updateEdgeWaypoints(id, []);
316→        return;
317→      }
318→      if (corners.every((w, i) => waypoints[i] && w.x === waypoints[i].x && w.y === waypoints[i].y)) return;
319→      updateEdgeWaypoints(id, corners);
320→    } else {
321→      // User-customized step edge (3+ waypoints from double-click): delta-based adjustment
322→      const updated = waypoints.map(w => ({ ...w }));
323→      const wp0 = updated[0];
324→      const wpLast = updated[updated.length - 1];
325→
326→      const firstIsVertical = Math.abs(prev.sx - wp0.x) <= Math.abs(prev.sy - wp0.y);
327→
328→      if (firstIsVertical) {
329→        wp0.x = Math.round(sourceX);
330→        wpLast.x = Math.round(targetX);
331→        const midY = computeMid(sourceY, targetY, sourcePosition, targetPosition, Position.Bottom);
332→        wp0.y = midY;
333→        wpLast.y = midY;
334→      } else {
335→        wp0.y = Math.round(sourceY);
336→        wpLast.y = Math.round(targetY);
337→        const midX = computeMid(sourceX, targetX, sourcePosition, targetPosition, Position.Right);
338→        wp0.x = midX;
339→        wpLast.x = midX;
340→      }
341→
342→      for (let i = 1; i < updated.length - 1; i++) {
343→        updated[i].x += Math.round((sdx + tdx) / 2);
344→        updated[i].y += Math.round((sdy + tdy) / 2);
345→      }
346→
347→      if (updated.every((w, i) => w.x === waypoints[i].x && w.y === waypoints[i].y)) return;
348→      updateEdgeWaypoints(id, updated);
349→    }
350→  }, [sourceX, sourceY, targetX, targetY]); // eslint-disable-line react-hooks/exhaustive-deps
351→
352→  const label = data?.label ?? "";
353→  const [editing, setEditing] = useState(false);
354→  const [value, setValue] = useState(label);
355→  const inputRef = useRef<HTMLInputElement>(null);
356→  const updateEdgeLabel = useFlowStore((s) => s.updateEdgeLabel);
357→  const { screenToFlowPosition } = useReactFlow();
358→
359→  useEffect(() => {
360→    setValue(label);
361→  }, [label]);
362→
363→  useEffect(() => {
364→    const handler = (e: Event) => {
365→      const detail = (e as CustomEvent).detail;
366→      if (detail?.type === "edge" && detail?.id === id) {
367→        setEditing(true);
368→      }
369→    };
370→    window.addEventListener("flowmaid:startEdit", handler);
371→    return () => window.removeEventListener("flowmaid:startEdit", handler);
372→  }, [id]);
373→
374→  useEffect(() => {
375→    if (editing) {
376→      inputRef.current?.focus();
377→      inputRef.current?.select();
378→    }
379→  }, [editing]);
380→
381→  const commit = useCallback(() => {
382→    setEditing(false);
383→    updateEdgeLabel(id, value.trim());
384→  }, [id, value, updateEdgeLabel]);
385→
386→  const strokeColor = computeColor(data?.strokeColor, data?.strokeOpacity, data?.strokeLightness) ?? undefined;
387→  const strokeWidth = data?.strokeWidth ?? 2;
388→
389→  // Sparkle particles at target on new edge connection
390→  const isNewEdge = data?.isNew;
391→  const [sparkles, setSparkles] = useState<Array<{ angle: number; dist: number; size: number }>>([]);
392→  const [sparkleVisible, setSparkleVisible] = useState(false);
393→
394→  useEffect(() => {
395→    if (!isNewEdge) return;
396→    // Generate random sparkle data
397→    const PARTICLE_COUNT = 8;
398→    const particles = Array.from({ length: PARTICLE_COUNT }, (_, i) => ({
399→      angle: (Math.PI * 2 * i) / PARTICLE_COUNT + (Math.random() - 0.5) * 0.8,
400→      dist: 18 + Math.random() * 22,
401→      size: 2 + Math.random() * 2.5,
402→    }));
403→    setSparkles(particles);
404→    setSparkleVisible(false);
405→    // Double rAF ensures initial state is painted before triggering transition
406→    requestAnimationFrame(() => {
407→      requestAnimationFrame(() => setSparkleVisible(true));
408→    });
409→    // Clear flag and sparkles after animation
410→    const timer = setTimeout(() => {
411→      setSparkles([]);
412→      setSparkleVisible(false);
413→      const { edges: storeEdges } = useFlowStore.getState();
414→      useFlowStore.setState({
415→        edges: storeEdges.map((e) => e.id === id ? { ...e, data: { ...e.data, isNew: undefined } } : e),
416→      });
417→    }, 500);
418→    return () => clearTimeout(timer);
419→  }, [id, isNewEdge]);
420→
421→  // Double-click on step edge: add a new jog (2 waypoints) at clicked segment
422→  const handleEdgeDoubleClick = useCallback(
423→    (e: React.MouseEvent) => {
424→      if (edgeType !== "step") return;
425→      e.stopPropagation();
426→      const pos = screenToFlowPosition({ x: e.clientX, y: e.clientY });
427→      const clickPt: Waypoint = { x: Math.round(pos.x), y: Math.round(pos.y) };
428→      const allPts: Waypoint[] = [{ x: sourceX, y: sourceY }, ...waypoints, { x: targetX, y: targetY }];
429→      const segIdx = findClosestSegment(allPts, clickPt);
430→
431→      const a = allPts[segIdx];
432→      const b = allPts[segIdx + 1];
433→      const isHorizontal = Math.abs(a.y - b.y) < Math.abs(a.x - b.x);
434→
435→      // Insert 2 new waypoints to create a jog perpendicular to the segment
436→      let newWp1: Waypoint;
437→      let newWp2: Waypoint;
438→      if (isHorizontal) {
439→        // Horizontal segment → add vertical jog
440→        newWp1 = { x: clickPt.x, y: a.y };
441→        newWp2 = { x: clickPt.x, y: clickPt.y };
442→      } else {
443→        // Vertical segment → add horizontal jog
444→        newWp1 = { x: a.x, y: clickPt.y };
445→        newWp2 = { x: clickPt.x, y: clickPt.y };
446→      }
447→
448→      const updated = [...waypoints];
449→      // segIdx maps to waypoint insertion: waypoint index = segIdx (since allPts[0] is source)
450→      updated.splice(segIdx, 0, newWp1, newWp2);
451→      updateEdgeWaypoints(id, updated);
452→    },
453→    [id, edgeType, waypoints, sourceX, sourceY, targetX, targetY, screenToFlowPosition, updateEdgeWaypoints]
454→  );
455→
456→  // Build segments for drag handles
457→  const allPts: Waypoint[] = hasWaypoints
458→    ? [{ x: sourceX, y: sourceY }, ...waypoints, { x: targetX, y: targetY }]
459→    : [];
460→
461→  return (
462→    <>
463→      {/* Invisible wider path for easier clicking/double-clicking */}
464→      <path
465→        d={edgePath}
466→        fill="none"
467→        stroke="currentColor"
468→        strokeOpacity={0}
469→        strokeWidth={Math.max(strokeWidth, 2) + 16}
470→        className="react-flow__edge-interaction"
471→        onDoubleClick={(e) => {
472→          e.stopPropagation();
473→          setEditing(true);
474→        }}
475→        style={{ pointerEvents: "stroke" }}
476→      />
477→      {/* Selection glow (like node box-shadow) */}
478→      {selected && (
479→        <path
480→          d={edgePath}
481→          fill="none"
482→          stroke="var(--primary)"
483→          strokeWidth={strokeWidth + 10}
484→          strokeOpacity={0.4}
485→          strokeLinecap="round"
486→          strokeLinejoin="round"
487→          style={{ pointerEvents: "none" }}
488→        />
489→      )}
490→      <path
491→        d={edgePath}
492→        fill="none"
493→        strokeWidth={strokeWidth}
494→        markerEnd={markerEnd as string}
495→        markerStart={markerStart as string}
496→        style={{
497→          ...style,
498→          ...(strokeColor && { stroke: strokeColor }),
499→          strokeDasharray:
500→            data?.strokeStyle === "dashed" ? "8 4" :
501→            data?.strokeStyle === "dotted" ? "2 2" :
502→            undefined,
503→        }}
504→        className="react-flow__edge-path"
505→      />
506→      {/* Segment drag handles (only when selected, step edges with waypoints) */}
507→      {selected && hasWaypoints && allPts.map((_, segIdx) => {
508→        if (segIdx >= allPts.length - 1) return null;
509→        // Only middle segments (both endpoints are waypoints)
510→        const startIsWp = segIdx > 0;
511→        const endIsWp = segIdx + 1 < allPts.length - 1;
512→        if (!startIsWp || !endIsWp) return null;
513→        const p1 = allPts[segIdx];
514→        const p2 = allPts[segIdx + 1];
515→        return (
516→          <SegmentHandle
517→            key={segIdx}
518→            segIdx={segIdx}
519→            p1={p1}
520→            p2={p2}
521→            edgeId={id}
522→            waypoints={waypoints}
523→            updateEdgeWaypoints={updateEdgeWaypoints}
524→            screenToFlowPosition={screenToFlowPosition}
525→          />
526→        );
527→      })}
528→      <EdgeLabelRenderer>
529→        {(editing || label !== "") ? (
530→          <div
531→            className="nodrag nopan absolute bg-background border border-border rounded px-1 text-xs"
532→            style={{
533→              transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
534→              pointerEvents: "all",
535→              cursor: "pointer",
536→            }}
537→            onDoubleClick={(e) => {
538→              e.stopPropagation();
539→              setEditing(true);
540→            }}
541→          >
542→            {editing ? (
543→              <input
544→                ref={inputRef}
545→                className="bg-transparent text-center text-xs outline-none w-16"
546→                value={value}
547→                onChange={(e) => setValue(e.target.value)}
548→                onBlur={commit}
549→                onKeyDown={(e) => {
550→                  if (e.key === "Enter") commit();
551→                  if (e.key === "Escape") {
552→                    setValue(label);
553→                    setEditing(false);
554→                  }
555→                }}
556→              />
557→            ) : (
558→              <span>{label}</span>
559→            )}
560→          </div>
561→        ) : selected ? (
562→          <div
563→            className="nodrag nopan absolute rounded text-xs"
564→            style={{
565→              transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
566→              pointerEvents: "all",
567→              cursor: "pointer",
568→              border: "1px dashed var(--border)",
569→              opacity: 0.6,
570→              padding: "0 4px",
571→              color: "var(--muted-foreground)",
572→            }}
573→            onDoubleClick={(e) => {
574→              e.stopPropagation();
575→              setEditing(true);
576→            }}
577→          >
578→            +
579→          </div>
580→        ) : null}
581→        {/* Sparkle particles at target on new edge */}
582→        {sparkles.map((s, i) => {
583→          const dx = Math.cos(s.angle) * s.dist;
584→          const dy = Math.sin(s.angle) * s.dist;
585→          return (
586→            <div
587→              key={`sparkle-${i}`}
588→              style={{
589→                position: "absolute",
590→                left: 0,
591→                top: 0,
592→                width: s.size * 2,
593→                height: s.size * 2,
594→                pointerEvents: "none",
595→                transform: sparkleVisible
596→                  ? `translate(${targetX + dx - s.size}px, ${targetY + dy - s.size}px) scale(0.2)`
597→                  : `translate(${targetX - s.size}px, ${targetY - s.size}px) scale(1)`,
598→                opacity: sparkleVisible ? 0 : 1,
599→                transition: "transform 0.45s ease-out, opacity 0.45s ease-out",
600→                background: "#fbbf24",
601→                clipPath: "polygon(50% 0%, 65% 35%, 100% 50%, 65% 65%, 50% 100%, 35% 65%, 0% 50%, 35% 35%)",
602→              }}
603→            />
604→          );
605→        })}
606→      </EdgeLabelRenderer>
607→    </>
608→  );
