611→function SegmentHandle({
612→  segIdx,
613→  p1,
614→  p2,
615→  edgeId,
616→  waypoints,
617→  updateEdgeWaypoints,
618→  screenToFlowPosition,
619→}: {
620→  segIdx: number;
621→  p1: Waypoint;
622→  p2: Waypoint;
623→  edgeId: string;
624→  waypoints: Waypoint[];
625→  updateEdgeWaypoints: (id: string, wps: Waypoint[]) => void;
626→  screenToFlowPosition: (pos: { x: number; y: number }) => { x: number; y: number };
627→}) {
628→  const [hovered, setHovered] = useState(false);
629→  const [dragging, setDragging] = useState(false);
630→  const isHorizontal = Math.abs(p1.y - p2.y) < Math.abs(p1.x - p2.x);
631→  const mx = (p1.x + p2.x) / 2;
632→  const my = (p1.y + p2.y) / 2;
633→  const cursor = isHorizontal ? "ns-resize" : "ew-resize";
634→
635→  // Both endpoints are always waypoints (middle segment)
636→  const wpStartIdx = segIdx - 1;
637→  const wpEndIdx = segIdx;
638→
639→  const handlePointerDown = useCallback((e: React.PointerEvent) => {
640→    e.stopPropagation();
641→    e.preventDefault();
642→    setDragging(true);
643→    (e.currentTarget as Element).setPointerCapture(e.pointerId);
644→  }, []);
645→
646→  const handlePointerMove = useCallback((e: React.PointerEvent) => {
647→    if (!dragging) return;
648→    const pos = screenToFlowPosition({ x: e.clientX, y: e.clientY });
649→    const updated = waypoints.map(w => ({ ...w }));
650→
651→    if (isHorizontal) {
652→      const newY = Math.round(pos.y);
653→      if (wpStartIdx >= 0 && wpStartIdx < updated.length) updated[wpStartIdx].y = newY;
654→      if (wpEndIdx >= 0 && wpEndIdx < updated.length) updated[wpEndIdx].y = newY;
655→    } else {
656→      const newX = Math.round(pos.x);
657→      if (wpStartIdx >= 0 && wpStartIdx < updated.length) updated[wpStartIdx].x = newX;
658→      if (wpEndIdx >= 0 && wpEndIdx < updated.length) updated[wpEndIdx].x = newX;
659→    }
660→
661→    updateEdgeWaypoints(edgeId, updated);
662→  }, [dragging, isHorizontal, wpStartIdx, wpEndIdx, edgeId, waypoints, screenToFlowPosition, updateEdgeWaypoints]);
663→
664→  const handlePointerUp = useCallback(() => {
665→    setDragging(false);
666→    setHovered(false);
667→  }, []);
668→
669→  const segLen = Math.hypot(p2.x - p1.x, p2.y - p1.y);
670→  if (segLen < 5) return null;
671→
672→  const showIcon = hovered || dragging;
673→
674→  return (
675→    <>
676→      {/* Invisible wider hit area */}
677→      <line
678→        x1={p1.x} y1={p1.y}
679→        x2={p2.x} y2={p2.y}
680→        stroke="transparent"
681→        strokeWidth={16}
682→        style={{ cursor, pointerEvents: "all" }}
683→        onPointerEnter={() => setHovered(true)}
684→        onPointerLeave={() => { if (!dragging) setHovered(false); }}
685→        onPointerDown={handlePointerDown}
686→        onPointerMove={handlePointerMove}
687→        onPointerUp={handlePointerUp}
688→      />
689→      {/* Grab indicator at midpoint — only on hover */}
690→      {showIcon && (
691→        isHorizontal ? (
692→          <g style={{ pointerEvents: "none" }}>
693→            <line x1={mx - 6} y1={my - 3} x2={mx + 6} y2={my - 3} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
694→            <line x1={mx - 6} y1={my} x2={mx + 6} y2={my} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
695→            <line x1={mx - 6} y1={my + 3} x2={mx + 6} y2={my + 3} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
696→          </g>
697→        ) : (
698→          <g style={{ pointerEvents: "none" }}>
699→            <line x1={mx - 3} y1={my - 6} x2={mx - 3} y2={my + 6} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
700→            <line x1={mx} y1={my - 6} x2={mx} y2={my + 6} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
701→            <line x1={mx + 3} y1={my - 6} x2={mx + 3} y2={my + 6} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
702→          </g>
703→        )
704→      )}
705→    </>
706→  );
707→}
