 1→"use client";
 2→
 3→import { useState, useCallback, useEffect } from "react";
 4→import { PANEL_STATE_KEY } from "@/lib/constants";
 5→
 6→interface PanelState {
 7→  leftOpen: boolean;
 8→  rightOpen: boolean;
 9→  leftWidth: number;
10→  rightWidth: number;
11→}
12→
13→const defaults: PanelState = {
14→  leftOpen: true,
15→  rightOpen: true,
16→  leftWidth: 180,
17→  rightWidth: 320,
18→};
19→
20→export function usePanelState() {
21→  const [state, setState] = useState<PanelState>(defaults);
22→
23→  useEffect(() => {
24→    try {
25→      const stored = localStorage.getItem(PANEL_STATE_KEY);
26→      if (stored) {
27→        setState({ ...defaults, ...JSON.parse(stored) });
28→      }
29→    } catch {
30→      // ignore
31→    }
32→  }, []);
33→
34→  const persist = useCallback((next: PanelState) => {
35→    setState(next);
36→    try {
37→      localStorage.setItem(PANEL_STATE_KEY, JSON.stringify(next));
38→    } catch {
39→      // ignore
40→    }
41→  }, []);
42→
43→  const toggleLeft = useCallback(() => {
44→    persist({ ...state, leftOpen: !state.leftOpen });
45→  }, [state, persist]);
46→
47→  const toggleRight = useCallback(() => {
48→    persist({ ...state, rightOpen: !state.rightOpen });
49→  }, [state, persist]);
50→
51→  const areBothClosed = !state.leftOpen && !state.rightOpen;
52→
53→  const toggleBothPanels = useCallback(() => {
54→    if (areBothClosed) {
55→      persist({ ...state, leftOpen: true, rightOpen: true });
56→    } else {
57→      persist({ ...state, leftOpen: false, rightOpen: false });
58→    }
59→  }, [state, areBothClosed, persist]);
60→
61→  return { ...state, toggleLeft, toggleRight, areBothClosed, toggleBothPanels };
62→}
