 93→export function FlowCanvas({ gridSnap = false, ghostEnabled = true }: { gridSnap?: boolean; ghostEnabled?: boolean }) {
 94→  perfCount("FlowCanvas");
 95→  const nodes = useFlowStore((s) => s.nodes);
 96→  const edges = useFlowStore((s) => s.edges);
 97→  const onNodesChange = useFlowStore((s) => s.onNodesChange);
 98→  const onEdgesChange = useFlowStore((s) => s.onEdgesChange);
 99→  const addEdge = useFlowStore((s) => s.addEdge);
100→  const addNode = useFlowStore((s) => s.addNode);
101→  const reconnectEdge = useFlowStore((s) => s.reconnectEdge);
102→
103→  const placeComponentInstance = useFlowStore((s) => s.placeComponentInstance);
104→  const [dragPayload] = useDnDContext();
105→  const reactFlowInstance = useRef<ReactFlowInstance<FlowNode, FlowEdge> | null>(null);
106→  const { menu, open: openMenu, close: closeMenu } = useContextMenu();
107→  const { guides, onNodeDrag, applySnap, clearGuides } = useSnapGuides(nodes, gridSnap);
108→
109→  // Predictive input: compute all valid ghost nodes for all directions
110→  const addNodeWithData = useFlowStore((s) => s.addNodeWithData);
111→  const DIRECTIONS: PredictiveDirection[] = useMemo(() => ["top", "right", "bottom", "left"], []);
112→  const OVERLAP_MARGIN = 10;
113→
114→  // Global candidate index for Tab cycling (applies to all visible ghosts)
115→  const [ghostCandidateIndex, setGhostCandidateIndex] = useState(0);
116→  const isDraggingRef = useRef(false);
117→
118→  // Cache candidates per source node (for Tab cycling)
119→  const candidatesMap = useMemo(() => {
120→    const map: Record<string, ReturnType<typeof computeCandidates>> = {};
121→    for (const node of nodes) {
122→      if (node.id.startsWith(GHOST_NODE_ID)) continue;
123→      if (node.data.componentParentId) continue;
124→      map[node.id] = computeCandidates(node, edges, nodes);
125→    }
126→    return map;
127→  }, [nodes, edges]);
128→
129→  const allGhosts = useMemo(() => {
130→    const ghostNodes: FlowNode[] = [];
131→    const ghostEdges: FlowEdge[] = [];
132→
133→    // Hide ghosts when disabled or while dragging
134→    if (!ghostEnabled || isDraggingRef.current) return { ghostNodes, ghostEdges };
135→
136→    // Show ghosts only when exactly one node is selected (exclude text nodes — used as memos)
137→    const selectedNodes = nodes.filter((n) => n.selected && !n.id.startsWith(GHOST_NODE_ID) && !n.data.componentParentId && n.data.shape !== "text");
138→    const selectedNode = selectedNodes.length === 1 ? selectedNodes[0] : undefined;
139→    if (selectedNode) {
140→      const node = selectedNode;
141→      const candidates = candidatesMap[node.id];
142→      if (!candidates || candidates.length === 0) return { ghostNodes, ghostEdges };
143→
144→      for (const dir of DIRECTIONS) {
145→        // Component instances: only show ghosts in the component's flow direction
146→        if (node.data.componentDefinitionId) {
147→          const compDir = (node.data.componentDefinitionDirection as string) ?? "TD";
148→          if (compDir === "TD" && (dir === "left" || dir === "right")) continue;
149→          if (compDir === "LR" && (dir === "top" || dir === "bottom")) continue;
150→        }
151→
152→        // Pick candidate: use global cycled index for all ghosts
153→        const ghostKey = `${node.id}_${dir}`;
154→        const candIdx = ((ghostCandidateIndex % candidates.length) + candidates.length) % candidates.length;
155→        const candidate = candidates[candIdx];
156→
157→        // Skip if edge already connected in this direction
158→        const hasEdge = edges.some((e) => {
159→          if (e.data?.isBridgeEdge) return false;
160→          return (e.source === node.id && e.sourceHandle === `${dir}-source`) ||
161→                 (e.target === node.id && e.targetHandle === `${dir}-target`);
162→        });
163→        if (hasEdge) continue;
164→
165→        // Compute ghost position
166→        const ghostPos = computeGhostPosition(node, dir, candidate.nodeData.shape);
167→
168→        // Skip if overlapping existing node
169→        const hasOverlap = nodes.some((other) => {
170→          if (other.id === node.id || other.id.startsWith(GHOST_NODE_ID)) return false;
171→          if (other.data.componentParentId) return false;
172→          const ow = other.measured?.width ?? (other.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
173→          const oh = other.measured?.height ?? (other.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
174→          return ghostPos.x < other.position.x + ow - OVERLAP_MARGIN &&
175→                 ghostPos.x + ghostPos.gw > other.position.x + OVERLAP_MARGIN &&
176→                 ghostPos.y < other.position.y + oh - OVERLAP_MARGIN &&
177→                 ghostPos.y + ghostPos.gh > other.position.y + OVERLAP_MARGIN;
178→        });
179→        if (hasOverlap) continue;
180→
181→        const ghostId = `${GHOST_NODE_ID}${ghostKey}`;
182→        const handles = DIRECTION_HANDLES[dir];
183→        const ghostSize = getGhostSize(node, candidate.nodeData.shape);
184→
185→        ghostNodes.push({
186→          id: ghostId,
187→          type: candidate.nodeData.shape,
188→          position: { x: ghostPos.x, y: ghostPos.y },
189→          width: ghostSize.width,
190→          height: ghostSize.height,
191→          data: {
192→            ...candidate.nodeData,
193→            label: "...",
194→            ghostTargetHandle: handles.targetHandle,
195→            ghostSourceNodeId: node.id,
196→            ghostDirection: dir,
197→            ghostCandidateIndex: candIdx,
198→          },
199→          style: { width: ghostSize.width, height: ghostSize.height },
200→          selectable: false,
201→          draggable: false,
202→        });
203→
204→        ghostEdges.push({
205→          id: `__ghost_edge__${ghostKey}`,
206→          source: node.id,
207→          target: ghostId,
208→          sourceHandle: handles.sourceHandle,
209→          targetHandle: handles.targetHandle,
210→          type: "labeled",
211→          style: { strokeDasharray: "6 3" },
212→          selectable: false,
213→          markerEnd: { type: MarkerType.ArrowClosed },
214→          data: {
215→            edgeType: candidate.edgeData?.edgeType ?? "bezier",
216→            markerEnd: candidate.edgeData?.markerEnd ?? "arrowclosed",
217→            markerStart: candidate.edgeData?.markerStart,
218→            strokeStyle: "dashed",
219→          },
220→        } as FlowEdge);
221→      }
222→    }
223→
224→    return { ghostNodes, ghostEdges };
225→  }, [nodes, edges, DIRECTIONS, OVERLAP_MARGIN, candidatesMap, ghostCandidateIndex, ghostEnabled]);
226→
227→  const hasGhosts = allGhosts.ghostNodes.length > 0;
228→
229→  // Inject ghost nodes/edges into arrays for rendering
230→  const nodesWithGhost = useMemo(
231→    () => allGhosts.ghostNodes.length > 0 ? [...nodes, ...allGhosts.ghostNodes] : nodes,
232→    [nodes, allGhosts.ghostNodes],
233→  );
234→  const edgesWithGhost = useMemo(
235→    () => allGhosts.ghostEdges.length > 0 ? [...edges, ...allGhosts.ghostEdges] : edges,
236→    [edges, allGhosts.ghostEdges],
237→  );
238→
239→  // Minimap toggle (persisted in localStorage, default: hidden)
240→  const [showMinimap, setShowMinimap] = useState(() => {
241→    if (typeof window === "undefined") return false;
242→    return localStorage.getItem(MINIMAP_STORAGE_KEY) === "true";
243→  });
244→  const toggleMinimap = useCallback(() => {
245→    setShowMinimap((prev) => {
246→      const next = !prev;
247→      localStorage.setItem(MINIMAP_STORAGE_KEY, String(next));
248→      return next;
249→    });
250→  }, []);
251→
252→  // Help panel toggle
253→  const [showHelp, setShowHelp] = useState(false);
254→  const toggleHelp = useCallback(() => setShowHelp((p) => !p), []);
255→  const { t } = useLocale();
256→
257→  // Track edge reconnection initiated from ring handles
258→  const reconnectingEdgeRef = useRef<FlowEdge | null>(null);
259→  const reconnectingTypeRef = useRef<"source" | "target" | null>(null);
260→
261→  const setEdgeVisibility = useCallback((edgeId: string | null, hidden: boolean) => {
262→    if (!edgeId) return;
263→    const edgeEl = document.querySelector(`.react-flow__edge[data-id="${CSS.escape(edgeId)}"]`);
264→    if (hidden) {
265→      edgeEl?.classList.add("reconnecting");
266→    } else {
267→      edgeEl?.classList.remove("reconnecting");
268→    }
269→  }, []);
270→
271→  const onConnectStart = useCallback(
272→    (_event: MouseEvent | TouchEvent, params: { nodeId: string | null; handleId: string | null; handleType: "source" | "target" | null }) => {
273→      if (!params.nodeId || !params.handleId || !params.handleType) return;
274→      const currentEdges = useFlowStore.getState().edges;
275→      // Reconnect priority:
276→      // 1. Selected edge at this position (same pos, either source or target handle) → always reconnect
277→      //    Handles at the same position overlap visually, so user may grab the "wrong" one
278→      // 2. Exactly one edge on the dragged handle → reconnect it
279→      // 3. Multiple edges on handle + one selected → reconnect the selected one
280→      // 4. Otherwise → new connection mode
281→      const handlePos = params.handleId.split("-")[0]; // e.g. "bottom" from "bottom-source"
282→      const sourceHandleId = `${handlePos}-source`;
283→      const targetHandleId = `${handlePos}-target`;
284→
285→      // Priority 1: selected edge at this position (check both source and target handles)
286→      const selectedAtPos = currentEdges.find((e) => {
287→        if (!e.selected || e.data?.isBridgeEdge) return false;
288→        return (e.source === params.nodeId && e.sourceHandle === sourceHandleId) ||
289→               (e.target === params.nodeId && e.targetHandle === targetHandleId);
290→      });
291→
292→      let connectedEdge: FlowEdge | undefined;
293→      let actualReconnectType: "source" | "target" | null = null;
294→
295→      if (selectedAtPos) {
296→        connectedEdge = selectedAtPos;
297→        // Determine which side of the edge connects to this node at this position
298→        actualReconnectType = (selectedAtPos.source === params.nodeId && selectedAtPos.sourceHandle === sourceHandleId)
299→          ? "source" : "target";
300→      } else {
301→        // Priority 2-3: fall back to edges on the exact dragged handle
302→        const edgesOnHandle = currentEdges.filter((e) => {
303→          if (e.data?.isBridgeEdge) return false;
304→          if (params.handleType === "source") return e.source === params.nodeId && e.sourceHandle === params.handleId;
305→          return e.target === params.nodeId && e.targetHandle === params.handleId;
306→        });
307→        connectedEdge = edgesOnHandle.length === 1
308→          ? edgesOnHandle[0]
309→          : edgesOnHandle.find((e) => e.selected);
310→        actualReconnectType = connectedEdge ? params.handleType : null;
311→      }
312→
313→      reconnectingEdgeRef.current = connectedEdge ?? null;
314→      reconnectingTypeRef.current = actualReconnectType;
315→      reconnectFixedEnd = null;
316→      if (connectedEdge && actualReconnectType) {
317→        setEdgeVisibility(connectedEdge.id, true);
318→        // Calculate the FIXED endpoint (the end NOT being dragged) for connection line rendering
319→        const fixedType = actualReconnectType === "source" ? "target" : "source";
320→        const fixedNodeId = fixedType === "source" ? connectedEdge.source : connectedEdge.target;
321→        const fixedHandleId = fixedType === "source" ? connectedEdge.sourceHandle : connectedEdge.targetHandle;
322→        if (fixedNodeId && fixedHandleId && reactFlowInstance.current) {
323→          const handleEl = document.querySelector(
324→            `.react-flow__node[data-id="${CSS.escape(fixedNodeId)}"] .react-flow__handle[data-handleid="${CSS.escape(fixedHandleId)}"]`
325→          );
326→          if (handleEl) {
327→            const rect = handleEl.getBoundingClientRect();
328→            const pos = reactFlowInstance.current.screenToFlowPosition({
329→              x: rect.x + rect.width / 2,
330→              y: rect.y + rect.height / 2,
331→            });
332→            // Determine the Position enum from handle ID (e.g. "top-source" → Position.Top)
333→            const posStr = fixedHandleId.split("-")[0] as "top" | "right" | "bottom" | "left";
334→            const posMap: Record<string, import("@xyflow/react").Position> = {
335→              top: Position.Top, right: Position.Right, bottom: Position.Bottom, left: Position.Left,
336→            };
337→            reconnectFixedEnd = { x: pos.x, y: pos.y, position: posMap[posStr] ?? Position.Top };
338→          }
339→        }
340→      }
341→    },
342→    [setEdgeVisibility]
343→  );
344→
345→  const onConnect = useCallback(
346→    (connection: Connection) => {
347→      if (!connection.source || !connection.target) return;
348→      // Ignore connections to/from ghost nodes (predictive input previews)
349→      if (connection.source.startsWith(GHOST_NODE_ID) || connection.target.startsWith(GHOST_NODE_ID)) return;
350→      const oldEdge = reconnectingEdgeRef.current;
351→      const reconnectType = reconnectingTypeRef.current;
352→      if (oldEdge && reconnectType) {
353→        // Determine which node in the connection is the new drop target
354→        const origNodeId = reconnectType === "source" ? oldEdge.source : oldEdge.target;
355→        const oldHandleId = reconnectType === "source" ? oldEdge.sourceHandle : oldEdge.targetHandle;
356→
357→        let newNodeId: string;
358→        let newHandle: string | null;
359→
360→        if (connection.source === connection.target) {
361→          // Same node: pick the handle that differs from the original
362→          newNodeId = connection.source!;
363→          const candidate = [connection.sourceHandle, connection.targetHandle].find(h => h && h !== oldHandleId);
364→          newHandle = candidate ?? null;
365→        } else {
366→          newNodeId = connection.source === origNodeId ? connection.target! : connection.source!;
367→          newHandle = connection.source === origNodeId ? connection.targetHandle : connection.sourceHandle;
368→        }
369→
370→        // Normalize handle ID suffix: React Flow may swap source/target in the connection object,
371→        // so the handle ID might have the wrong type suffix (e.g. "top-source" when we need "top-target")
372→        if (newHandle) {
373→          const pos = newHandle.split("-")[0];
374→          newHandle = `${pos}-${reconnectType}`;
375→        }
376→
377→        // Guard: if no valid handle found, abort reconnection
378→        if (!newHandle) return;
379→
380→        const newConnection: Connection = reconnectType === "source"
381→          ? { source: newNodeId, sourceHandle: newHandle, target: oldEdge.target, targetHandle: oldEdge.targetHandle ?? null }
382→          : { source: oldEdge.source, sourceHandle: oldEdge.sourceHandle ?? null, target: newNodeId, targetHandle: newHandle };
383→
384→        reconnectEdge(oldEdge, newConnection);
385→        setEdgeVisibility(oldEdge.id, false);
386→        reconnectingEdgeRef.current = null;
387→        reconnectingTypeRef.current = null;
388→        reconnectFixedEnd = null;
389→      } else {
390→        // Normalize handle IDs: React Flow may swap source/target when dragging from a target handle,
391→        // causing sourceHandle to have "-target" suffix and vice versa
392→        let srcHandle = connection.sourceHandle;
393→        let tgtHandle = connection.targetHandle;
394→        if (srcHandle) {
395→          const pos = srcHandle.split("-")[0];
396→          srcHandle = `${pos}-source`;
397→        }
398→        if (tgtHandle) {
399→          const pos = tgtHandle.split("-")[0];
400→          tgtHandle = `${pos}-target`;
401→        }
402→        addEdge(
403→          connection.source,
404→          connection.target,
405→          undefined,
406→          srcHandle,
407→          tgtHandle,
408→        );
409→      }
410→    },
411→    [addEdge, reconnectEdge, setEdgeVisibility]
412→  );
413→
414→  const onConnectEnd = useCallback(() => {
415→    if (reconnectingEdgeRef.current) {
416→      setEdgeVisibility(reconnectingEdgeRef.current.id, false);
417→      reconnectingEdgeRef.current = null;
418→      reconnectingTypeRef.current = null;
419→    }
420→    reconnectFixedEnd = null;
421→  }, [setEdgeVisibility]);
422→
423→  const onDragOver = useCallback((event: React.DragEvent) => {
424→    event.preventDefault();
425→    event.dataTransfer.dropEffect = "move";
426→  }, []);
427→
428→  const onDrop = useCallback(
429→    (event: React.DragEvent) => {
430→      event.preventDefault();
431→      if (!dragPayload || !reactFlowInstance.current) return;
432→
433→      const position = reactFlowInstance.current.screenToFlowPosition({
434→        x: event.clientX,
435→        y: event.clientY,
436→      });
437→
438→      let newNodeId: string | undefined;
439→      if (dragPayload.kind === "component") {
440→        newNodeId = placeComponentInstance(dragPayload.value, position);
441→      } else {
442→        addNode(dragPayload.value, position);
443→      }
444→
445→      // Deselect all, then select the new node after animation completes
446→      const { nodes: currentNodes, onNodesChange: applyChanges } = useFlowStore.getState();
447→      applyChanges(currentNodes.map((n) => ({ id: n.id, type: "select" as const, selected: false })));
448→      setTimeout(() => {
449→        const { nodes: latestNodes, onNodesChange: apply } = useFlowStore.getState();
450→        // For components, use the returned parent ID; for regular nodes, use the last added
451→        const targetId = newNodeId ?? latestNodes[latestNodes.length - 1]?.id;
452→        if (targetId) {
453→          apply(latestNodes.map((n) => ({ id: n.id, type: "select" as const, selected: n.id === targetId })));
454→        }
455→      }, 250);
456→    },
457→    [dragPayload, addNode, placeComponentInstance]
458→  );
459→
460→  const onNodeDragStart = useCallback(() => {
461→    isDraggingRef.current = true;
462→    useFlowStore.temporal.getState().pause();
463→  }, []);
464→
465→  const onNodeDragStop = useCallback(
466→    () => {
467→      isDraggingRef.current = false;
468→      useFlowStore.temporal.getState().resume();
469→      clearGuides();
470→    },
471→    [clearGuides]
472→  );
473→
474→  // Delete key handler — animate selected nodes before removing
475→  useEffect(() => {
476→    const handleKeyDown = (e: KeyboardEvent) => {
477→      if (e.key !== "Delete" && e.key !== "Backspace") return;
478→      // Don't trigger if user is typing in an input/textarea
479→      const tag = (e.target as HTMLElement)?.tagName;
480→      if (tag === "INPUT" || tag === "TEXTAREA") return;
481→      e.preventDefault();
482→      const state = useFlowStore.getState();
483→      const selectedNodeIds = state.nodes.filter((n) => n.selected && !n.data.isLocked && !n.data.componentParentId).map((n) => n.id);
484→      const selectedEdgeIds = state.edges.filter((e) => e.selected).map((e) => e.id);
485→      if (selectedNodeIds.length > 0) {
486→        animateDeleteNodes(selectedNodeIds);
487→      }
