33→function reconcileBridgeEdges(nodes: FlowNode[], edges: FlowEdge[], defs: ComponentDefinition[], direction: FlowDirection = "TD"): FlowEdge[] {
34→  // Remove all existing bridge edges
35→  const nonBridgeEdges = edges.filter((e) => !e.data?.isBridgeEdge);
36→
37→  // Generate bridge edges for all component instances
38→  const allBridgeEdges: FlowEdge[] = [];
39→  for (const node of nodes) {
40→    if (node.type !== "componentInstance" || !node.data.componentDefinitionId) continue;
41→    const def = defs.find((d) => d.id === node.data.componentDefinitionId);
42→    if (!def) continue;
43→
44→    const bridges = generateBridgeEdges({
45→      parentId: node.id,
46→      def,
47→      allEdges: nonBridgeEdges,
48→      direction: def.direction ?? direction,
49→    });
50→
51→    // If instance is collapsed, hide bridge edges
52→    const isCollapsed = node.data.collapsed ?? false;
53→    for (const b of bridges) {
54→      if (isCollapsed) b.hidden = true;
55→      allBridgeEdges.push(b);
56→    }
57→  }
58→
59→  return [...nonBridgeEdges, ...allBridgeEdges];
60→}
