  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { FlowDirection, NodeShape } from "@/types/flow";
  3→import { MarkerType } from "@xyflow/react";
  4→import {
  5→  DEFAULT_NODE_WIDTH,
  6→  DEFAULT_NODE_HEIGHT,
  7→  DEFAULT_DIAMOND_SIZE,
  8→} from "@/lib/constants";
  9→import { idToCounter } from "@/lib/id";
 10→import { autoLayout } from "./autoLayout";
 11→import type { MermaidLayoutResult } from "./renderLayout";
 12→
 13→/**
 14→ * Reverse of escapeMermaid: convert Mermaid escape sequences back to original characters.
 15→ */
 16→export function unescapeMermaid(text: string): string {
 17→  let result = text
 18→    .replace(/#amp;/g, "&")
 19→    .replace(/#quot;/g, '"')
 20→    .replace(/#lt;/g, "<")
 21→    .replace(/#gt;/g, ">")
 22→    .replace(/#lbrace;/g, "{")
 23→    .replace(/#rbrace;/g, "}")
 24→    .replace(/#lpar;/g, "(")
 25→    .replace(/#rpar;/g, ")")
 26→    .replace(/#lbrack;/g, "[")
 27→    .replace(/#rbrack;/g, "]");
 28→  // Strip surrounding double quotes (Mermaid quoted labels), but only if length > 2
 29→  if (result.length > 2 && result.startsWith('"') && result.endsWith('"')) {
 30→    result = result.slice(1, -1);
 31→  }
 32→  // Convert <br/> and <br> to newline
 33→  result = result.replace(/<br\s*\/?>/gi, "\n");
 34→  return result;
 35→}
 36→
 37→// Shape patterns ordered from most specific (longest delimiters) to least specific
 38→const SHAPE_PATTERNS: { open: string; close: string; shape: NodeShape }[] = [
 39→  { open: "((", close: "))", shape: "circle" },
 40→  { open: "([", close: "])", shape: "stadium" },
 41→  { open: "[(", close: ")]", shape: "cylinder" },
 42→  { open: "[[", close: "]]", shape: "predefinedProcess" },
 43→  { open: "{{", close: "}}", shape: "hexagon" },
 44→  { open: "[/", close: "\\]", shape: "document" },
 45→  { open: "[\\", close: "/]", shape: "manualInput" },
 46→  { open: "[/", close: "/]", shape: "parallelogram" },
 47→  { open: "[\\", close: "\\]", shape: "trapezoid" },
 48→  { open: "{", close: "}", shape: "diamond" },
 49→  { open: "(", close: ")", shape: "roundedRect" },
 50→  { open: "[", close: "]", shape: "rectangle" },
 51→];
 52→
 53→function parseNodeDef(raw: string): { id: string; label: string; shape: NodeShape } | null {
 54→  const trimmed = raw.trim();
 55→  if (!trimmed) return null;
 56→
 57→  for (const { open, close, shape } of SHAPE_PATTERNS) {
 58→    const openIdx = trimmed.indexOf(open);
 59→    if (openIdx < 1) continue;
 60→
 61→    const id = trimmed.slice(0, openIdx);
 62→    // Verify the rest ends with close
 63→    const rest = trimmed.slice(openIdx + open.length);
 64→    if (!rest.endsWith(close)) continue;
 65→
 66→    const label = unescapeMermaid(rest.slice(0, rest.length - close.length));
 67→    return { id, label, shape };
 68→  }
 69→
 70→  // No shape delimiters: just an ID reference
 71→  return null;
 72→}
 73→
 74→function getNodeSize(shape: NodeShape): { width: number; height: number } {
 75→  switch (shape) {
 76→    case "diamond":
 77→      return { width: DEFAULT_DIAMOND_SIZE, height: DEFAULT_DIAMOND_SIZE };
 78→    case "circle":
 79→      return { width: DEFAULT_NODE_HEIGHT * 2, height: DEFAULT_NODE_HEIGHT * 2 };
 80→    case "hexagon":
 81→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT + 10 };
 82→    case "cylinder":
 83→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 20 };
 84→    case "document":
 85→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 10 };
 86→    case "predefinedProcess":
 87→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 88→    case "display":
 89→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 90→    default:
 91→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT };
 92→  }
 93→}
 94→
 95→// Split an edge line by arrow patterns, returning segments and labels
 96→// Supports: -->, -.->, ===>, ~~>, -->, etc.
 97→const ARROW_RE = /\s*(?:-+\.?-*>|={2,}>|~{2,}>)\s*(?:\|([^|]*)\|)?\s*/;
 98→
 99→function splitEdgeLine(line: string): { segments: string[]; labels: string[] } | null {
100→  const segments: string[] = [];
101→  const labels: string[] = [];
102→  let remaining = line;
103→
104→  while (true) {
105→    const match = ARROW_RE.exec(remaining);
106→    if (!match) {
107→      segments.push(remaining.trim());
108→      break;
109→    }
110→    segments.push(remaining.slice(0, match.index).trim());
111→    labels.push(match[1] ?? "");
112→    remaining = remaining.slice(match.index + match[0].length);
113→  }
114→
115→  if (segments.length < 2) return null;
116→  return { segments, labels };
117→}
118→
119→/**
120→ * Sort nodes so that parent nodes come before their children.
121→ * React Flow requires this ordering for parentId relationships to work correctly.
122→ */
123→function sortNodesParentFirst(nodes: FlowNode[]): void {
124→  nodes.sort((a, b) => {
125→    // Nodes without parentId come first
126→    if (!a.parentId && b.parentId) return -1;
127→    if (a.parentId && !b.parentId) return 1;
128→    // If b is a child of a, a comes first
129→    if (b.parentId === a.id) return -1;
130→    if (a.parentId === b.id) return 1;
131→    return 0;
132→  });
133→}
134→
135→// Subgraph padding constants for bounding box calculation
136→const SUBGRAPH_PADDING_X = 40;
137→const SUBGRAPH_PADDING_Y_TOP = 40;
138→const SUBGRAPH_PADDING_Y_BOTTOM = 20;
139→
140→export function parseMermaid(text: string, edgeType?: import("@/types/flow").EdgeType, layout?: MermaidLayoutResult): {
141→  nodes: FlowNode[];
142→  edges: FlowEdge[];
143→  direction: FlowDirection;
144→  nextIdCounter: number;
145→  componentDefinitions: import("@/types/flow").ComponentDefinition[];
146→} {
147→  const lines = text.split("\n").map((l) => l.trim()).filter((l) => l.length > 0);
148→  if (lines.length === 0) throw new Error("Empty input");
149→
150→  // Parse direction from first line
151→  const headerMatch = lines[0].match(/^(?:graph|flowchart)\s+(TD|LR|TB|BT)$/i);
152→  if (!headerMatch) throw new Error("Invalid header: expected 'graph TD|LR' or 'flowchart TD|LR'");
153→
154→  let direction: FlowDirection = "TD";
155→  const dirStr = headerMatch[1].toUpperCase();
156→  if (dirStr === "LR") direction = "LR";
157→  // TB and BT both map to TD
158→
159→  // Collect node definitions and edges
160→  const nodeDefs = new Map<string, { label: string; shape: NodeShape }>();
161→  const edgeList: { source: string; target: string; label: string }[] = [];
162→
163→  function registerNode(id: string, label: string, shape: NodeShape) {
164→    // First definition wins for shape/label
165→    if (!nodeDefs.has(id)) {
166→      nodeDefs.set(id, { label, shape });
167→    }
168→  }
169→
170→  function ensureNode(id: string) {
171→    if (!nodeDefs.has(id)) {
172→      nodeDefs.set(id, { label: id, shape: "rectangle" });
173→    }
174→  }
175→
176→  function resolveNodeRef(segment: string): string {
177→    const parsed = parseNodeDef(segment);
178→    if (parsed) {
179→      registerNode(parsed.id, parsed.label, parsed.shape);
180→      return parsed.id;
181→    }
182→    // Plain ID reference
183→    const id = segment.trim();
184→    ensureNode(id);
185→    return id;
186→  }
187→
188→  // Track subgraph contexts for subgraphGroup creation
189→  const subgraphStack: { id: string; label: string }[] = [];
190→  const subgraphLabels = new Map<string, string>();
191→  const nodeToSubgraph = new Map<string, string>();
192→  // Track parent subgraph for nested subgraphs
193→  const subgraphParentMap = new Map<string, string>();
194→
195→  for (let i = 1; i < lines.length; i++) {
196→    const line = lines[i];
197→
198→    // Check for subgraph start
199→    const subgraphMatch = line.match(/^subgraph\s+(\S+?)(?:\[([^\]]*)\])?\s*$/);
200→    if (subgraphMatch) {
201→      const sgId = subgraphMatch[1];
202→      const rawLabel = subgraphMatch[2] ?? sgId;
203→      const sgLabel = unescapeMermaid(rawLabel);
204→      // Track parent subgraph for nesting
205→      if (subgraphStack.length > 0) {
206→        subgraphParentMap.set(sgId, subgraphStack[subgraphStack.length - 1].id);
207→      }
208→      subgraphStack.push({ id: sgId, label: sgLabel });
209→      subgraphLabels.set(sgId, sgLabel);
210→      continue;
211→    }
212→
213→    // Check for end
214→    if (line === "end" && subgraphStack.length > 0) {
215→      subgraphStack.pop();
216→      continue;
217→    }
218→
219→    const currentSubgraph = subgraphStack.length > 0 ? subgraphStack[subgraphStack.length - 1].id : null;
220→
221→    // Try to parse as edge line (contains -->)
222→    const edgeParts = splitEdgeLine(line);
223→    if (edgeParts && edgeParts.segments.length >= 2) {
224→      const { segments, labels } = edgeParts;
225→      const resolvedIds = segments.map((s) => resolveNodeRef(s));
226→
227→      for (const rid of resolvedIds) {
228→        if (currentSubgraph && !nodeToSubgraph.has(rid)) {
229→          nodeToSubgraph.set(rid, currentSubgraph);
230→        }
231→      }
232→
233→      for (let j = 0; j < resolvedIds.length - 1; j++) {
234→        edgeList.push({
235→          source: resolvedIds[j],
236→          target: resolvedIds[j + 1],
237→          label: labels[j] ?? "",
238→        });
239→      }
240→      continue;
241→    }
242→
243→    // Try to parse as standalone node definition
244→    const parsed = parseNodeDef(line);
245→    if (parsed) {
246→      registerNode(parsed.id, parsed.label, parsed.shape);
247→      if (currentSubgraph && !nodeToSubgraph.has(parsed.id)) {
248→        nodeToSubgraph.set(parsed.id, currentSubgraph);
249→      }
250→    }
251→  }
252→
253→  // Remove nodeDefs entries that conflict with subgraph IDs
254→  // (When a subgraph ID is used as an edge endpoint, ensureNode creates a regular node entry,
255→  //  but the subgraph should be represented as a subgraphGroup node instead)
256→  for (const sgId of subgraphLabels.keys()) {
257→    nodeDefs.delete(sgId);
258→  }
259→
260→  // Layout: use mermaid.js layout if provided, otherwise fall back to autoLayout
261→  let positions: Map<string, { x: number; y: number }>;
262→  let backEdges: Set<string> = new Set<string>();
263→  const sizeMap = new Map<string, { width: number; height: number }>();
264→
265→  if (layout) {
266→    // Use mermaid.js layout result
267→    positions = new Map<string, { x: number; y: number }>();
268→    backEdges = new Set<string>();
269→
270→    for (const [id, def] of nodeDefs) {
271→      const mNode = layout.nodes.get(id);
272→      if (mNode) {
273→        // mermaid.js returns center coordinates; convert to top-left
274→        positions.set(id, {
275→          x: mNode.x - mNode.width / 2,
276→          y: mNode.y - mNode.height / 2,
277→        });
278→        sizeMap.set(id, { width: mNode.width, height: mNode.height });
279→      } else {
280→        const size = getNodeSize(def.shape);
281→        positions.set(id, { x: 0, y: 0 });
282→        sizeMap.set(id, size);
283→      }
284→    }
285→  } else {
286→    // Fall back to autoLayout
287→    const nodeIds = [...nodeDefs.keys()].map((id) => ({ id }));
288→    for (const [id, def] of nodeDefs) {
289→      sizeMap.set(id, getNodeSize(def.shape));
290→    }
291→    const layoutResult = autoLayout(nodeIds, edgeList, direction, sizeMap);
292→    positions = layoutResult.positions;
293→    backEdges = layoutResult.backEdges;
294→  }
295→
296→  // Build FlowNode[]
297→  const nodes: FlowNode[] = [];
298→  let maxCounter = 0;
299→
300→  for (const [id, def] of nodeDefs) {
301→    const pos = positions.get(id) ?? { x: 0, y: 0 };
302→    const size = sizeMap.get(id) ?? getNodeSize(def.shape);
303→
304→    // Track highest alphabetic ID counter
305→    if (/^[A-Z]+$/.test(id)) {
306→      const counter = idToCounter(id);
307→      if (counter + 1 > maxCounter) maxCounter = counter + 1;
308→    }
309→
310→    nodes.push({
311→      id,
312→      type: def.shape,
313→      position: pos,
314→      data: { label: def.label, shape: def.shape },
315→      style: { width: size.width, height: size.height },
316→    });
317→  }
318→
319→  // Handle directions: forward edges follow main axis, back-edges loop via cross axis
320→  const fwdSourceHandle = direction === "LR" ? "right-source" : "bottom-source";
321→  const fwdTargetHandle = direction === "LR" ? "left-target" : "top-target";
322→  const backSourceHandle = direction === "LR" ? "bottom-source" : "right-source";
323→  const backTargetHandle = direction === "LR" ? "bottom-target" : "right-target";
324→
325→  // Build FlowEdge[]
326→  const edges: FlowEdge[] = [];
327→  for (const e of edgeList) {
328→    const isBack = backEdges.has(`${e.source}->${e.target}`);
329→    const sh = isBack ? backSourceHandle : fwdSourceHandle;
330→    const th = isBack ? backTargetHandle : fwdTargetHandle;
331→    const edgeId = `${e.source}-${e.target}-${sh}-${th}`;
332→    edges.push({
333→      id: edgeId,
334→      source: e.source,
335→      target: e.target,
336→      sourceHandle: sh,
337→      targetHandle: th,
338→      type: "labeled",
339→      markerEnd: { type: MarkerType.ArrowClosed },
340→      data: {
341→        label: e.label,
342→        edgeType: edgeType ?? "bezier",
343→        markerEnd: "arrowclosed",
344→      },
345→    });
346→  }
347→
348→  // Convert subgraphs to subgraphGroup nodes with child parentId relationships
349→  // Two-pass approach:
350→  //   Pass 1 (innermost first): Create subgraphGroup nodes with absolute positions, record sizes
351→  //   Pass 2 (outermost first): Convert positions to relative coordinates
352→
353→  // Store absolute positions and sizes of each subgraph
354→  const sgAbsPositions = new Map<string, { x: number; y: number }>();
355→  const sgSizes = new Map<string, { width: number; height: number }>();
356→
357→  // Build processing order: innermost first (post-order DFS)
358→  // Post-order ensures children are pushed before parents → innermost first without reversing
359→  const sgProcessOrder: string[] = [];
360→  const sgProcessed = new Set<string>();
361→  const enqueueSg = (sgId: string) => {
362→    if (sgProcessed.has(sgId)) return;
363→    sgProcessed.add(sgId);
364→    // Recurse into children first
365→    for (const [nestedSgId, parentSgId] of subgraphParentMap) {
366→      if (parentSgId === sgId) enqueueSg(nestedSgId);
367→    }
368→    // Push self after children (post-order: innermost first)
369→    sgProcessOrder.push(sgId);
370→  };
371→  // Start from root subgraphs (those without parents)
372→  for (const sgId of subgraphLabels.keys()) {
373→    if (!subgraphParentMap.has(sgId)) enqueueSg(sgId);
374→  }
375→  // Also process any orphan subgraphs
376→  for (const sgId of subgraphLabels.keys()) enqueueSg(sgId);
377→
378→  // Pass 1: Create subgraphGroup nodes with absolute positions (innermost first)
379→  for (const sgId of sgProcessOrder) {
380→    const sgLabel = subgraphLabels.get(sgId)!;
381→
382→    // Collect direct child node IDs for this subgraph
383→    const childNodeIds = new Set<string>();
384→    for (const [nodeId, parentSgId] of nodeToSubgraph) {
385→      if (parentSgId === sgId) childNodeIds.add(nodeId);
386→    }
387→
388→    // Get direct child nodes (regular nodes only)
389→    const childNodes = nodes.filter((n) => childNodeIds.has(n.id));
390→
391→    // Also include nested subgraph group nodes whose parent is this subgraph
392→    const nestedSgIds: string[] = [];
393→    for (const [nestedSgId, parentSgId] of subgraphParentMap) {
394→      if (parentSgId === sgId) nestedSgIds.push(nestedSgId);
395→    }
396→
397→    // Compute absolute position and size of this subgraph
398→    let sgAbsPos: { x: number; y: number };
399→    let sgSize: { width: number; height: number };
400→
401→    const sgLayout = layout?.subgraphs.get(sgId);
402→    if (sgLayout) {
403→      sgAbsPos = { x: sgLayout.x, y: sgLayout.y };
404→      sgSize = { width: sgLayout.width, height: sgLayout.height };
405→    } else {
406→      // Compute bounding box from child positions (all absolute at this point)
407→      let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
408→      // Include regular child nodes
409→      for (const child of childNodes) {
410→        const w = (child.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
411→        const h = (child.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
412→        if (child.position.x < minX) minX = child.position.x;
413→        if (child.position.y < minY) minY = child.position.y;
414→        if (child.position.x + w > maxX) maxX = child.position.x + w;
415→        if (child.position.y + h > maxY) maxY = child.position.y + h;
416→      }
417→      // Include nested subgraph groups (already created in nodes by innermost-first order)
418→      for (const nestedSgId of nestedSgIds) {
419→        const nestedAbsPos = sgAbsPositions.get(nestedSgId);
420→        const nestedSize = sgSizes.get(nestedSgId);
421→        if (nestedAbsPos && nestedSize) {
422→          if (nestedAbsPos.x < minX) minX = nestedAbsPos.x;
423→          if (nestedAbsPos.y < minY) minY = nestedAbsPos.y;
424→          if (nestedAbsPos.x + nestedSize.width > maxX) maxX = nestedAbsPos.x + nestedSize.width;
425→          if (nestedAbsPos.y + nestedSize.height > maxY) maxY = nestedAbsPos.y + nestedSize.height;
426→        }
427→      }
428→
429→      if (minX === Infinity) {
430→        sgAbsPos = { x: 0, y: 0 };
431→        sgSize = { width: 200, height: 100 };
432→      } else {
433→        sgAbsPos = {
434→          x: minX - SUBGRAPH_PADDING_X,
435→          y: minY - SUBGRAPH_PADDING_Y_TOP,
436→        };
437→        sgSize = {
438→          width: (maxX - minX) + SUBGRAPH_PADDING_X * 2,
439→          height: (maxY - minY) + SUBGRAPH_PADDING_Y_TOP + SUBGRAPH_PADDING_Y_BOTTOM,
440→        };
441→      }
442→    }
443→
444→    sgAbsPositions.set(sgId, sgAbsPos);
445→    sgSizes.set(sgId, sgSize);
446→
447→    // Create subgraphGroup node with absolute position (will be converted to relative in Pass 2)
448→    const parentSgId = subgraphParentMap.get(sgId);
449→    const sgNode: FlowNode = {
450→      id: sgId,
451→      type: "subgraphGroup",
452→      position: { ...sgAbsPos }, // absolute; converted to relative in Pass 2
453→      data: { label: sgLabel, shape: "rectangle" as NodeShape, isSubgraphGroup: true },
454→      style: { width: sgSize.width, height: sgSize.height },
455→      zIndex: -1,
456→    };
457→
458→    if (parentSgId) {
459→      sgNode.parentId = parentSgId;
460→      sgNode.data.subgraphParentId = parentSgId;
461→    }
462→
463→    nodes.push(sgNode);
464→
465→    // Set parentId and subgraphParentId on child nodes (positions stay absolute for now)
466→    for (const child of childNodes) {
467→      child.parentId = sgId;
468→      child.data = { ...child.data, subgraphParentId: sgId };
469→    }
470→  }
471→
472→  // Pass 2: Convert all positions from absolute to relative (outermost first)
473→  // Process outermost first so that when we convert a child's position,
474→  // we subtract the parent's absolute position (not yet modified)
475→  const sgOutermostFirst = [...sgProcessOrder].reverse();
476→  for (const sgId of sgOutermostFirst) {
477→    const sgAbsPos = sgAbsPositions.get(sgId)!;
478→
479→    // Convert this subgraphGroup node's position to relative (if nested)
480→    const parentSgId = subgraphParentMap.get(sgId);
481→    if (parentSgId) {
482→      const parentAbsPos = sgAbsPositions.get(parentSgId)!;
483→      const sgNode = nodes.find((n) => n.id === sgId);
484→      if (sgNode) {
485→        sgNode.position = {
486→          x: sgAbsPos.x - parentAbsPos.x,
487→          y: sgAbsPos.y - parentAbsPos.y,
488→        };
489→      }
490→    }
491→
492→    // Convert direct child nodes' positions to relative to this subgraph
493→    for (const [nodeId, parentSg] of nodeToSubgraph) {
494→      if (parentSg !== sgId) continue;
495→      const child = nodes.find((n) => n.id === nodeId);
496→      if (child) {
497→        child.position = {
498→          x: child.position.x - sgAbsPos.x,
499→          y: child.position.y - sgAbsPos.y,
500→        };
501→      }
502→    }
503→  }
504→
505→  // Sort nodes so parents come before children (React Flow requires this for parentId)
506→  sortNodesParentFirst(nodes);
507→
508→  return {
509→    nodes,
510→    edges,
511→    direction,
512→    nextIdCounter: maxCounter,
513→    componentDefinitions: [],
514→  };
515→}
