  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { FlowDirection, ComponentDefinition } from "@/types/flow";
  3→import { nodeToMermaid } from "./nodeToMermaid";
  4→import { escapeMermaid } from "./nodeToMermaid";
  5→import { edgeToMermaid } from "./edgeToMermaid";
  6→
  7→/**
  8→ * Recursively emit a subgraph block for a subgraphGroup node.
  9→ * Handles arbitrary nesting depth. Edges are output at the level where
 10→ * both source and target are direct children (not deeper descendants).
 11→ */
 12→function emitSubgraphBlock(
 13→  sgId: string,
 14→  sgLabel: string,
 15→  nodes: FlowNode[],
 16→  edges: FlowEdge[],
 17→  lines: string[],
 18→): void {
 19→  lines.push(`    subgraph ${sgId}[${escapeMermaid(sgLabel)}]`);
 20→
 21→  const children = nodes.filter((n) => n.data.subgraphParentId === sgId);
 22→  // All direct children IDs (both regular nodes and nested subgraphGroups)
 23→  const allDirectChildIds = new Set<string>();
 24→
 25→  for (const child of children) {
 26→    if (child.data.shape === "text") continue;
 27→    allDirectChildIds.add(child.id);
 28→    if (child.data.isSubgraphGroup) {
 29→      // Recurse into nested subgraph
 30→      emitSubgraphBlock(child.id, child.data.label, nodes, edges, lines);
 31→    } else {
 32→      lines.push(nodeToMermaid(child));
 33→    }
 34→  }
 35→
 36→  // Output edges where both endpoints are direct children of this group
 37→  // (includes edges between regular nodes and nested subgraphGroup nodes)
 38→  for (const edge of edges) {
 39→    if (edge.data?.isBridgeEdge) continue;
 40→    if (allDirectChildIds.has(edge.source) && allDirectChildIds.has(edge.target)) {
 41→      lines.push(edgeToMermaid(edge));
 42→    }
 43→  }
 44→
 45→  lines.push(`    end`);
 46→}
 47→
 48→/**
 49→ * Generate complete Mermaid flowchart syntax from nodes, edges, and direction
 50→ */
 51→export function generateMermaid(
 52→  nodes: FlowNode[],
 53→  edges: FlowEdge[],
 54→  direction: FlowDirection,
 55→  definitions?: ComponentDefinition[]
 56→): string {
 57→  const lines: string[] = [`flowchart ${direction}`];
 58→
 59→  // Build map of component instance IDs to their child nodes
 60→  const instanceChildMap = new Map<string, FlowNode[]>();
 61→  const childNodeIds = new Set<string>();
 62→  for (const node of nodes) {
 63→    if (node.data.componentParentId) {
 64→      const parentId = node.data.componentParentId as string;
 65→      if (!instanceChildMap.has(parentId)) instanceChildMap.set(parentId, []);
 66→      instanceChildMap.get(parentId)!.push(node);
 67→      childNodeIds.add(node.id);
 68→    }
 69→  }
 70→
 71→  // Build set of subgraph child node IDs
 72→  const subgraphChildIds = new Set<string>();
 73→  for (const node of nodes) {
 74→    if (node.data.subgraphParentId) {
 75→      subgraphChildIds.add(node.id);
 76→    }
 77→  }
 78→
 79→  for (const node of nodes) {
 80→    if (node.data.shape === "text") continue;
 81→    // Skip component children (they're handled within their parent's subgraph)
 82→    if (node.data.componentParentId) continue;
 83→    // Skip subgraph children (they're handled within their parent's subgraph block)
 84→    if (node.data.subgraphParentId) continue;
 85→
 86→    // Subgraph group: output as subgraph block with child nodes (recursive for nesting)
 87→    if (node.data.isSubgraphGroup) {
 88→      emitSubgraphBlock(node.id, node.data.label, nodes, edges, lines);
 89→      continue;
 90→    }
 91→
 92→    // Component instance: expand as subgraph using definition (including Start/End)
 93→    if (node.type === "componentInstance" && node.data.componentDefinitionId) {
 94→      const instanceLabel = escapeMermaid(node.data.componentInstanceName as string ?? node.data.label);
 95→      lines.push(`    subgraph ${node.id}[${instanceLabel}]`);
 96→
 97→      // Get definition to include all nodes (including entry/exit which are excluded from canvas)
 98→      const def = definitions?.find((d) => d.id === node.data.componentDefinitionId);
 99→      if (def) {
100→        // Output all nodes from definition (including Start/End)
101→        for (const defNode of def.nodes) {
102→          const childId = `${node.id}_${defNode.id}`;
103→          const label = escapeMermaid(defNode.label);
104→          const shape = defNode.shape;
105→          let nodeLine: string;
106→          switch (shape) {
107→            case "diamond":
108→              nodeLine = `    ${childId}{${label}}`;
109→              break;
110→            case "roundedRect":
111→              nodeLine = `    ${childId}(${label})`;
112→              break;
113→            case "circle":
114→              nodeLine = `    ${childId}((${label}))`;
115→              break;
116→            case "stadium":
117→              nodeLine = `    ${childId}([${label}])`;
118→              break;
119→            default:
120→              nodeLine = `    ${childId}[${label}]`;
121→          }
122→          lines.push(nodeLine);
123→        }
124→
125→        // Output all internal edges from definition (including Start/End edges)
126→        for (const defEdge of def.edges) {
127→          const srcId = `${node.id}_${defEdge.source}`;
128→          const tgtId = `${node.id}_${defEdge.target}`;
129→          const label = defEdge.label;
130→          if (label) {
131→            lines.push(`    ${srcId} -->|${escapeMermaid(label)}| ${tgtId}`);
132→          } else {
133→            lines.push(`    ${srcId} --> ${tgtId}`);
134→          }
135→        }
136→      } else {
137→        // Fallback: use actual child nodes if definition not found
138→        const children = instanceChildMap.get(node.id) ?? [];
139→        for (const child of children) {
140→          const label = escapeMermaid(child.data.label);
141→          const shape = child.data.shape;
142→          let nodeLine: string;
143→          switch (shape) {
144→            case "diamond":
145→              nodeLine = `    ${child.id}{${label}}`;
146→              break;
147→            case "roundedRect":
148→              nodeLine = `    ${child.id}(${label})`;
149→              break;
150→            case "circle":
151→              nodeLine = `    ${child.id}((${label}))`;
152→              break;
153→            case "stadium":
154→              nodeLine = `    ${child.id}([${label}])`;
155→              break;
156→            default:
157→              nodeLine = `    ${child.id}[${label}]`;
158→          }
159→          lines.push(nodeLine);
160→        }
161→
162→        for (const edge of edges) {
163→          if (childNodeIds.has(edge.source) && childNodeIds.has(edge.target)) {
164→            const srcNode = nodes.find((n) => n.id === edge.source);
165→            const tgtNode = nodes.find((n) => n.id === edge.target);
166→            if (srcNode?.data.componentParentId === node.id && tgtNode?.data.componentParentId === node.id) {
167→              const label = edge.data?.label;
168→              if (label) {
169→                lines.push(`    ${edge.source} -->|${escapeMermaid(label)}| ${edge.target}`);
170→              } else {
171→                lines.push(`    ${edge.source} --> ${edge.target}`);
172→              }
173→            }
174→          }
175→        }
176→      }
177→
178→      lines.push(`    end`);
179→      continue;
180→    }
181→
182→    lines.push(nodeToMermaid(node));
183→  }
184→
185→  for (const edge of edges) {
186→    // Skip bridge edges
187→    if (edge.data?.isBridgeEdge) continue;
188→    // Skip internal edges (already handled in component subgraph)
189→    if (childNodeIds.has(edge.source) && childNodeIds.has(edge.target)) continue;
190→    // Skip edges between subgraph children that share the same direct parent
191→    // (already handled in their subgraph block). Cross-subgraph edges are output here.
192→    if (subgraphChildIds.has(edge.source) && subgraphChildIds.has(edge.target)) {
193→      const srcNode = nodes.find((n) => n.id === edge.source);
194→      const tgtNode = nodes.find((n) => n.id === edge.target);
195→      const srcParent = srcNode?.data.subgraphParentId as string | undefined;
196→      const tgtParent = tgtNode?.data.subgraphParentId as string | undefined;
197→      if (srcParent && tgtParent && srcParent === tgtParent) continue;
198→    }
199→
200→    // For edges connected to component instances, remap to entry/exit child nodes
201→    if (definitions) {
202→      let source = edge.source;
203→      let target = edge.target;
204→
205→      const sourceNode = nodes.find((n) => n.id === source);
206→      const targetNode = nodes.find((n) => n.id === target);
207→
208→      if (sourceNode?.type === "componentInstance" && sourceNode.data.componentDefinitionId) {
209→        const def = definitions.find((d) => d.id === sourceNode.data.componentDefinitionId);
210→        if (def?.exitNodeId) {
211→          source = `${sourceNode.id}_${def.exitNodeId}`;
212→        }
213→      }
214→      if (targetNode?.type === "componentInstance" && targetNode.data.componentDefinitionId) {
215→        const def = definitions.find((d) => d.id === targetNode.data.componentDefinitionId);
216→        if (def?.entryNodeId) {
217→          target = `${targetNode.id}_${def.entryNodeId}`;
218→        }
219→      }
220→
221→      if (source !== edge.source || target !== edge.target) {
222→        const label = edge.data?.label;
223→        if (label) {
224→          lines.push(`    ${source} -->|${escapeMermaid(label)}| ${target}`);
225→        } else {
226→          lines.push(`    ${source} --> ${target}`);
227→        }
228→        continue;
229→      }
230→    }
231→
232→    lines.push(edgeToMermaid(edge));
233→  }
234→
235→  return lines.join("\n");
236→}
