 12→export function getDefaultSize(shape: string): { width: number; height: number } {
 13→  if (shape === "diamond") return { width: DEFAULT_DIAMOND_SIZE, height: DEFAULT_DIAMOND_SIZE };
 14→  if (shape === "circle") return { width: DEFAULT_DIAMOND_SIZE, height: DEFAULT_DIAMOND_SIZE };
 15→  if (shape === "hexagon") return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 16→  if (shape === "cylinder") return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 20 };
 17→  if (shape === "predefinedProcess" || shape === "display") return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 18→  return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT };
