 21→/** Get the size for a ghost node. If the ghost shape matches the source,
 22→ *  inherit the source's actual size; otherwise use the shape's default. */
 23→export function getGhostSize(sourceNode: FlowNode, ghostShape: string): { width: number; height: number } {
 24→  if (ghostShape === sourceNode.data.shape) {
 25→    return {
 26→      width: sourceNode.width ?? sourceNode.measured?.width ?? (sourceNode.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH,
 27→      height: sourceNode.height ?? sourceNode.measured?.height ?? (sourceNode.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT,
 28→    };
 29→  }
 30→  return getDefaultSize(ghostShape);
