 33→export function computeGhostPosition(
 34→  sourceNode: FlowNode,
 35→  direction: PredictiveDirection,
 36→  ghostShape: string,
 37→): { x: number; y: number; gw: number; gh: number } {
 38→  const w = sourceNode.width ?? sourceNode.measured?.width ?? (sourceNode.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
 39→  const h = sourceNode.height ?? sourceNode.measured?.height ?? (sourceNode.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
 40→  const ghostSize = getGhostSize(sourceNode, ghostShape);
 41→  const gw = ghostSize.width;
 42→  const gh = ghostSize.height;
 43→
 44→  switch (direction) {
 45→    case "bottom":
 46→      return { x: sourceNode.position.x + (w - gw) / 2, y: sourceNode.position.y + h + PREDICTIVE_GAP_PX, gw, gh };
 47→    case "top":
 48→      return { x: sourceNode.position.x + (w - gw) / 2, y: sourceNode.position.y - gh - PREDICTIVE_GAP_PX, gw, gh };
 49→    case "right":
 50→      return { x: sourceNode.position.x + w + PREDICTIVE_GAP_PX, y: sourceNode.position.y + (h - gh) / 2, gw, gh };
 51→    case "left":
 52→      return { x: sourceNode.position.x - gw - PREDICTIVE_GAP_PX, y: sourceNode.position.y + (h - gh) / 2, gw, gh };
 53→  }
 54→}
