 56→/**
 57→ * Compute predictive input candidates for a source node.
 58→ * Returns up to 4 candidates (duplicates by shape removed).
 59→ */
 60→export function computeCandidates(
 61→  sourceNode: FlowNode,
 62→  allEdges: FlowEdge[],
 63→  allNodes: FlowNode[],
 64→): PredictiveCandidate[] {
 65→  const candidates: PredictiveCandidate[] = [];
 66→  const seenShapes = new Set<NodeShape>();
 67→
 68→  const srcData = sourceNode.data;
 69→
 70→  // Find an existing edge from this source to derive edge style
 71→  const outEdge = allEdges.find(
 72→    (e) => e.source === sourceNode.id && !e.data?.isBridgeEdge,
 73→  );
 74→  const outEdgeData: Partial<FlowEdgeData> = outEdge?.data
 75→    ? {
 76→        edgeType: outEdge.data.edgeType,
 77→        markerStart: outEdge.data.markerStart,
 78→        markerEnd: outEdge.data.markerEnd,
 79→        strokeWidth: outEdge.data.strokeWidth,
 80→        strokeColor: outEdge.data.strokeColor,
 81→        strokeStyle: outEdge.data.strokeStyle,
 82→      }
 83→    : {};
 84→
 85→  // 1. Full copy (style + label)
 86→  const fullCopyData: FlowNodeData = {
 87→    label: "",  // will be replaced with new ID
 88→    shape: srcData.shape,
 89→    ...(srcData.fillColor && { fillColor: srcData.fillColor }),
 90→    ...(srcData.fillOpacity !== undefined && { fillOpacity: srcData.fillOpacity }),
 91→    ...(srcData.fillLightness !== undefined && { fillLightness: srcData.fillLightness }),
 92→    ...(srcData.borderColor && { borderColor: srcData.borderColor }),
 93→    ...(srcData.borderOpacity !== undefined && { borderOpacity: srcData.borderOpacity }),
 94→    ...(srcData.borderLightness !== undefined && { borderLightness: srcData.borderLightness }),
 95→    ...(srcData.borderWidth && { borderWidth: srcData.borderWidth }),
 96→    ...(srcData.borderStyle && { borderStyle: srcData.borderStyle }),
 97→    ...(srcData.fontSize && { fontSize: srcData.fontSize }),
 98→    ...(srcData.textColor && { textColor: srcData.textColor }),
 99→    ...(srcData.textOpacity !== undefined && { textOpacity: srcData.textOpacity }),
100→    ...(srcData.textLightness !== undefined && { textLightness: srcData.textLightness }),
101→    ...(srcData.textAlign && { textAlign: srcData.textAlign }),
102→    ...(srcData.textVerticalAlign && { textVerticalAlign: srcData.textVerticalAlign }),
103→    ...(srcData.bold && { bold: srcData.bold }),
104→    ...(srcData.italic && { italic: srcData.italic }),
105→    ...(srcData.underline && { underline: srcData.underline }),
106→  };
107→  candidates.push({ kind: "fullCopy", nodeData: fullCopyData, edgeData: outEdgeData });
108→  seenShapes.add(srcData.shape);
109→
110→  // 2. Shape only copy (skip if source has no custom style — would be identical to fullCopy)
111→  const hasCustomStyle = !!(
112→    srcData.fillColor || srcData.fillOpacity !== undefined || srcData.fillLightness !== undefined ||
113→    srcData.borderColor || srcData.borderOpacity !== undefined || srcData.borderLightness !== undefined ||
114→    srcData.borderWidth || srcData.borderStyle ||
115→    srcData.fontSize || srcData.textColor || srcData.textOpacity !== undefined || srcData.textLightness !== undefined ||
116→    srcData.textAlign || srcData.textVerticalAlign || srcData.bold || srcData.italic || srcData.underline
117→  );
118→  if (hasCustomStyle) {
119→    const shapeCopyData: FlowNodeData = {
120→      label: "",
121→      shape: srcData.shape,
122→    };
123→    candidates.push({ kind: "shapeCopy", nodeData: shapeCopyData, edgeData: {} });
124→  }
125→
126→  // 3-4. Pair frequency candidates
127→  const pairShapes = computePairFrequencies(srcData.shape, allEdges, allNodes);
128→  for (let i = 0; i < pairShapes.length && candidates.length < 4; i++) {
129→    const shape = pairShapes[i];
130→    if (seenShapes.has(shape)) continue;
131→    seenShapes.add(shape);
132→    const kind = candidates.length === 2 ? "pairFreq1" as const : "pairFreq2" as const;
133→    candidates.push({
134→      kind,
135→      nodeData: { label: "", shape },
136→      edgeData: {},
137→    });
138→  }
139→
140→  // Fill with rectangle (処理) if not yet at 4 candidates
141→  if (candidates.length < 4 && !seenShapes.has("rectangle")) {
142→    candidates.push({ kind: "pairFreq1", nodeData: { label: "", shape: "rectangle" }, edgeData: {} });
143→    seenShapes.add("rectangle");
144→  }
145→
146→  // Fill with diamond (条件分岐) if not yet at 4 candidates
147→  if (candidates.length < 4 && !seenShapes.has("diamond")) {
148→    candidates.push({ kind: "pairFreq2", nodeData: { label: "", shape: "diamond" }, edgeData: {} });
149→  }
150→
151→  return candidates;
152→}
153→
154→/**
155→ * Count edge pairs where source shape matches, return target shapes sorted by frequency.
156→ * Excludes "text" shape from results.
157→ */
158→function computePairFrequencies(
159→  sourceShape: NodeShape,
160→  allEdges: FlowEdge[],
161→  allNodes: FlowNode[],
162→): NodeShape[] {
163→  const nodeMap = new Map<string, FlowNode>();
164→  for (const n of allNodes) nodeMap.set(n.id, n);
165→
166→  const freq = new Map<NodeShape, number>();
167→  for (const edge of allEdges) {
168→    if (edge.data?.isBridgeEdge) continue;
169→    const src = nodeMap.get(edge.source);
170→    const tgt = nodeMap.get(edge.target);
171→    if (!src || !tgt) continue;
172→    if (src.data.shape !== sourceShape) continue;
173→    if (tgt.data.shape === "text") continue;
174→    freq.set(tgt.data.shape, (freq.get(tgt.data.shape) ?? 0) + 1);
175→  }
176→
177→  return [...freq.entries()]
178→    .sort((a, b) => b[1] - a[1])
179→    .map(([shape]) => shape);
180→}
