 54→function ReconnectConnectionLine({ fromX, fromY, toX, toY, fromPosition, toPosition }: ConnectionLineComponentProps<FlowNode>) {
 55→  let startX: number, startY: number, endX: number, endY: number;
 56→  let startPos = fromPosition;
 57→  let endPos = toPosition;
 58→
 59→  if (reconnectFixedEnd) {
 60→    // During reconnection: draw from fixed end to cursor
 61→    startX = reconnectFixedEnd.x;
 62→    startY = reconnectFixedEnd.y;
 63→    startPos = reconnectFixedEnd.position;
 64→    endX = toX;
 65→    endY = toY;
 66→    // Infer target position from direction so bezier doesn't overshoot cursor
 67→    endPos = inferTargetPosition(startX, startY, endX, endY);
 68→  } else {
 69→    // Normal connection: draw from drag origin to cursor
 70→    startX = fromX;
 71→    startY = fromY;
 72→    endX = toX;
 73→    endY = toY;
 74→    endPos = inferTargetPosition(startX, startY, endX, endY);
 75→  }
 76→
 77→  const [path] = getBezierPath({
 78→    sourceX: startX,
 79→    sourceY: startY,
 80→    sourcePosition: startPos,
 81→    targetX: endX,
 82→    targetY: endY,
 83→    targetPosition: endPos,
 84→  });
 85→
 86→  return (
 87→    <g>
 88→      <path d={path} fill="none" stroke="var(--primary)" strokeWidth={2} strokeDasharray="6 3" />
 89→    </g>
 90→  );
 91→}
