103→ * Sync React Flow's internal nodeLookup/edgeLookup to match our selection state.
104→ *
105→ * React Flow's `getSelectionChanges(items, ids, mutateItem=true)` directly mutates
106→ * `internalNode.selected` in nodeLookup. When we block those changes (e.g. blocking
107→ * resetSelectedElements during Ctrl+drag), the internal state diverges from our props.
108→ *
109→ * On re-render, `adoptUserNodes` with `checkEquality: true` reuses internal nodes
110→ * when the userNode reference hasn't changed — preserving the stale `.selected` value.
111→ * This function repairs that divergence by directly setting `.selected` to match our state.
112→ */
113→function syncInternalSelection(
114→  ids: Set<string>,
115→  rfStore: { getState: () => { nodeLookup: Map<string, { id: string; selected?: boolean }>; edgeLookup: Map<string, { id: string; selected?: boolean }> } },
116→) {
117→  const { nodeLookup, edgeLookup } = rfStore.getState();
118→  for (const [id, node] of nodeLookup) {
119→    node.selected = ids.has(id);
120→  }
121→  for (const [id, edge] of edgeLookup) {
122→    edge.selected = ids.has(id);
123→  }
124→}
